window.MIRROR_DOSSIERS = {
 "abakua": {
  "essence": "An all-male initiatory brotherhood founded in 1836 in the port town of Regla, Havana, by enslaved and free Africans from the Cross River region (Calabar), re-establishing the Ékpè leopard society on Cuban soil. Its lodges (potencias/juegos) persist in Havana, Matanzas, and Cárdenas, and its central claim is custody of a divine Voice — first captured in the fish Tanze by the woman Sikán — now reproduced by the secret Ekue friction drum that only initiates may approach.",
  "cosmos": "The supreme creator Abasí stands remote; his power reaches humans as sound, the roar first embodied in Tanze and mechanically perpetuated in the Ekue after the fish died. The foundational pact was sealed by Sikán's sacrifice, and the anaforuana chalk ideograms re-activate that pact, mapping Cross River geography and ancestry onto Cuban ritual ground. The dead remain active: ancestors materialize as the mute, masked Íreme who cleanse the community and enforce its law.",
  "practice": "Membership is by male initiation (plante) under oaths of lifelong secrecy; each lodge guards its famba inner sanctum, its consecrated objects, and a liturgical language derived from Èfìk. Rites center on drumming, chalk-drawn firmas consecrating the space, animal offerings, and public Íreme masquerade; lodges double as mutual-aid societies, historically rooted among Havana and Matanzas dockworkers, and demand an ethic of discretion, loyalty, and upright manhood.",
  "canon": "No scripture: an oral corpus of myth, chant, and ritual speech, partly recorded in handwritten lodge notebooks (libretas); the foundational Sikán–Tanze narrative was documented by Lydia Cabrera and Fernando Ortiz.",
  "reflects": "The impulse to guard the sacred as a secret — divine presence held as sound and oath inside a closed brotherhood rather than published as doctrine.",
  "sources": [
   "Lydia Cabrera, 'La Sociedad Secreta Abakuá' (1959)",
   "Ivor L. Miller, 'Voice of the Leopard: African Secret Societies and Cuba' (2009)",
   "David H. Brown, 'The Light Inside: Abakuá Society Arts and Cuban Cultural History' (2003)"
  ]
 },
 "aboriginal": {
  "essence": "The religious life of the hundreds of distinct Aboriginal nations of Australia — not one doctrine but a family of Laws resting on a shared foundation, the Dreaming (Arrernte Altjira, Western Desert Tjukurpa): the ever-present order in which ancestral beings shaped the land and left it charged with Law. With a continuous cultural record of roughly 50,000 years, its custodians hold among the oldest living religious traditions on earth.",
  "cosmos": "The world was not created from nothing; ancestral beings emerged in the everywhen, walked and sang the country into shape, and remain present in the features and species they became. Land is therefore the primary sacred medium — songlines are the ancestors' routes held as sung verse — and each person is bound by conception or descent to particular country and its totemic beings. At death the spirit returns to its country and the Dreaming, with the details differing sharply from nation to nation.",
  "practice": "Religion is enacted rather than congregational: initiation with ordeal and graded revelation of secret-sacred knowledge, song and dance ceremony, increase rites for species, and custodial maintenance of sites (including the repainting of images such as the Kimberley Wandjina). Kinship and moiety systems regulate marriage, obligation, and ritual roles; knowledge is restricted by sex, age, and country, so much of the tradition is deliberately not public.",
  "canon": "An oral corpus of song cycles, narratives, and restricted ceremony — no script; 'the Dreaming' is W. E. H. Stanner's English coinage (1956) for concepts each language names in its own way.",
  "reflects": "The sacralization of place and time itself — religion as custodianship of land under an ever-present Law rather than belief in a creator or hope of another world.",
  "sources": [
   "W. E. H. Stanner, 'The Dreaming' (1956)",
   "T. G. H. Strehlow, 'Songs of Central Australia' (1971)",
   "W. Lloyd Warner, 'A Black Civilization' (1937)",
   "Tony Swain, 'A Place for Strangers' (1993)"
  ],
  "flagged": [
   "The ~50,000-year figure is archaeological (human presence in Australia), used here as a proxy for cultural continuity — religious continuity per se cannot be directly dated."
  ]
 },
 "abrahamic": {
  "essence": "The family of monotheisms — Judaism, Christianity, and Islam, with ancient Israelite religion as the root — that trace themselves to the God of Abraham. Together its branches claim over half the world's population; this record treats them as a composite shard, one covenantal lineage refracted into rival canons.",
  "cosmos": "One transcendent God creates the world by will or word, stands outside it, and acts within history — time runs in a line from creation toward judgment, not in cycles. Early Israelite religion knew only a shadowy Sheol; bodily resurrection and last judgment developed in the Second Temple period and became central to Christianity and Islam, while rabbinic Judaism holds resurrection alongside the world-to-come. Prophets and revealed scripture bridge the gulf between creator and creature.",
  "practice": "Each branch institutionalizes covenant differently: Torah observance, synagogue, and halakha in Judaism; sacraments, church, and creed in Christianity; the Five Pillars, mosque, and sharia in Islam. Common to all are congregational prayer, scriptural reading, fasting and festival calendars, almsgiving, and ethical demands understood as owed to God rather than negotiated with him.",
  "canon": "The Hebrew Bible (Tanakh); the Christian Bible adding the New Testament; the Qur'an — each surrounded by an authoritative interpretive corpus (Talmud, patristic writings, hadith).",
  "reflects": "The covenantal impulse: one exclusive God whose will is disclosed in scripture and whose arena is linear history — religion as binding contract between creator and community.",
  "sources": [
   "Mark S. Smith, 'The Early History of God' (1990)",
   "F. E. Peters, 'The Children of Abraham' (1982)",
   "Karen Armstrong, 'A History of God' (1993)"
  ]
 },
 "ainu": {
  "essence": "The animist religion of the Ainu, the indigenous people of Hokkaidō, Sakhalin, and the Kuril Islands, distinct from the Yamato Japanese in language and descent. Its central claim: the world is shared with kamuy — spirit-persons of fire, bear, orca, plants, and even tools — who visit the human land wearing bodies, and whose goodwill is kept by hospitality and correct send-off.",
  "cosmos": "Everything that acts has ramat, animating spirit; the kamuy are ramat at full intensity, dwelling in their own country (Kamuy Mosir) and visiting Ainu Mosir, the human world, disguised as animals, objects, and phenomena. Meat, pelts, and useful things are gifts a visiting kamuy leaves behind; killed game or a worn-out tool is not destroyed but released homeward with offerings so that it will return. The human dead likewise depart to an ancestral other-world, sent on by funeral rites with the hearth-fire as mediator.",
  "practice": "Worship is household- and village-scale, led by male elders rather than a priesthood: libations of sake, whittled willow prayer-sticks (inau) set up for particular kamuy, first-catch observances for salmon and game, and prayers routed through Kamuy-huci, the hearth-fire grandmother. The most elaborate rite was the iyomante, in which a bear cub raised as an honored guest was ceremonially killed and sent home laden with gifts. Meiji-era assimilation policy suppressed practice; revival movements carry it today.",
  "canon": "No script: the oral yukar and oina epics, chanted in the first person of gods and heroes, carry the theology; Chiri Yukie's 'Ainu Shin'yōshū' (1923) is the landmark written collection.",
  "reflects": "Reciprocal hospitality as the religious bond — divinity conceived as a guest to be hosted and sent home rather than a sovereign to be obeyed.",
  "sources": [
   "Neil Gordon Munro, 'Ainu Creed and Cult' (1962)",
   "John Batchelor, 'The Ainu and Their Folk-Lore' (1901)",
   "Donald L. Philippi, 'Songs of Gods, Songs of Humans' (1979)",
   "Chiri Yukie, 'Ainu Shin'yōshū' (1923)"
  ]
 },
 "akan": {
  "essence": "The religion of the Akan peoples of Ghana and Côte d'Ivoire — Asante (Ashanti), Fante, Akuapem, and kin — organized around a withdrawn sky-creator, Nyame, his delegated lesser gods (abosom), the Earth Asase Yaa, and above all the lineage ancestors (nsamanfo). It remains a living tradition, interwoven since the nineteenth century with Christianity.",
  "cosmos": "Nyame made the world and receded upward — the widely told tale blames an old woman's fufu pestle striking the sky — leaving daily governance to the abosom, his children seated in rivers, lakes, and shrines. The human person is composite: kra (life-soul from Nyame), sunsum (personality-spirit), mogya (mother's blood, fixing the matriclan), and ntoro (the father's line). One who lived well and receives proper funeral rites becomes an ancestor in Asamando, retaining real authority over the living lineage.",
  "practice": "Libation and offering are the core acts — to ancestors at blackened stools during the recurring Adae rites, and to abosom at shrines served by trained priests (akomfo) who speak for the god in possession trance. Thursday is traditionally kept from farm work as Asase Yaa's day, and funerals are the largest social-religious events, since they are what make ancestors. Among the Asante, the Golden Stool, held to house the nation's soul (sunsum), fuses religion with kingship.",
  "canon": "Oral: libation prayers, proverbs, drum poetry, and the Anansesem story corpus; the earliest systematic documentation is R. S. Rattray's Asante ethnography of the 1920s.",
  "reflects": "The sacred routed through lineage — a high god held in awe at a distance while daily religious traffic runs to ancestors and delegated powers close at hand.",
  "sources": [
   "R. S. Rattray, 'Religion and Art in Ashanti' (1927)",
   "J. B. Danquah, 'The Akan Doctrine of God' (1944)",
   "Kofi Asare Opoku, 'West African Traditional Religion' (1978)"
  ]
 },
 "alawite": {
  "essence": "An esoteric, initiatory offshoot of Shi'ite Islam (Nusayrism, after the ninth-century founder-figure Muhammad ibn Nusayr; doctrine consolidated by al-Khasibi, d. 969), carried by a community concentrated in the coastal mountains of Syria, with kin in Hatay (Turkey) and Lebanon. Its central claim is that the Godhead manifests as a triad — 'Ali as the Ma'na (Essence), Muhammad as the Ism (Name/Veil), Salman al-Farisi as the Bab (Gate) — a secret disclosed only to initiated men.",
  "cosmos": "Souls were originally lights in the divine presence that fell through doubting 'Ali's divinity; the material world is the purgatorial consequence, and the divine triad has appeared across cycles of history to call the fallen home. Souls transmigrate (tanasukh) through successive bodies: the purified ascend back to the luminous, astral realm, while historical enemies of the Imams recur as incarnations of darkness (the Amsal). The orthodox single resurrection-day is thereby replaced with a gradual, Gnostic-shaped ascent.",
  "practice": "Religion is transmitted by staged male initiation under sponsoring sheikhs; women are traditionally excluded from the doctrine. Worship happens in private houses and at hilltop shrine-tombs (ziyara) rather than mosques, includes a secret liturgy with consecrated wine (the Quddas), and sanctions taqiyya — protective dissimulation — under hostile rule. Festivals combine Shi'ite dates (Ghadir, Ashura) with Nawruz and some Christian feasts, reflecting the Levantine environment.",
  "canon": "Esoteric writings restricted to initiates, chiefly the liturgical compilation Kitab al-Majmu' (known publicly through an apostate's 1863 publication) and treatises of al-Khasibi's school; the Qur'an is retained but read allegorically.",
  "reflects": "Religion as guarded gnosis — the divine hidden behind veils and gates, with survival under persecution built into doctrine through secrecy and dissimulation.",
  "sources": [
   "Yaron Friedman, 'The Nusayri-Alawis: An Introduction to the Religion, History and Identity' (2010)",
   "Meir M. Bar-Asher & Aryeh Kofsky, 'The Nusayri-Alawi Religion' (2002)",
   "Matti Moosa, 'Extremist Shiites: The Ghulat Sects' (1988)"
  ],
  "flagged": [
   "Inner doctrine is known largely through hostile heresiography and defector texts (e.g. the 1863 Kitab al-Majmu' publication); details such as the fate of wicked souls in lower rebirths rest on that filtered evidence."
  ]
 },
 "alchemy": {
  "essence": "A tradition of operative and spiritual practice rather than a church: the art of perfecting matter, pursued from Greco-Egyptian Alexandria (pseudo-Democritus; Zosimos of Panopolis, c. 300 CE) through the Islamic world (the Jabirian corpus, al-Razi) into Latin Europe, with a partly independent Chinese counterpart (waidan/neidan) aimed at immortality. Its practitioners claimed base metals can be transmuted to gold by the Philosopher's Stone — and, in much of the tradition, that the work also perfects the worker.",
  "cosmos": "Underlying it is a unified matter theory: substances derive from one prima materia, metals 'ripen' toward gold in the earth, and the adept accelerates nature's own process. The cosmos is mirrored — macrocosm and microcosm correspond (the Emerald Tablet's 'as above, so below') — so laboratory operations double as movements of soul, staged as nigredo (blackening), albedo (whitening), and rubedo (reddening). Chinese alchemy made the stakes explicit in the elixir of physical immortality; the Western Stone promises transmutation, universal medicine, and regeneration.",
  "practice": "Practice was laboratory craft — distillation, calcination, sublimation, long regulated heating in furnace and sealed vessel — transmitted master-to-apprentice and armored in deliberate obscurity: cover-names (Decknamen), emblems, riddling texts. Many adepts fused benchwork with prayer and ascetic discipline; secrecy was itself an ethic, the art reserved for the worthy.",
  "canon": "A sprawling manuscript corpus rather than a scripture: the Emerald Tablet, the visions of Zosimos, the Turba Philosophorum, the Jabirian corpus, and illustrated compendia such as the Rosarium Philosophorum and Splendor Solis.",
  "reflects": "Salvation as labor — the religious impulse turned toward matter itself, seeking transcendence through the disciplined transformation of the physical world.",
  "sources": [
   "Lawrence M. Principe, 'The Secrets of Alchemy' (2013)",
   "Mircea Eliade, 'The Forge and the Crucible' (1956)",
   "C. G. Jung, 'Psychology and Alchemy' (1944)"
  ],
  "flagged": [
   "The 'spiritual alchemy' reading is contested: Principe and Newman argue most historical Western alchemy was straightforwardly chemical in intent, with the psycho-spiritual frame amplified by 19th–20th-century occultism and Jung."
  ]
 },
 "alevism": {
  "essence": "A heterodox tradition of Islamic lineage in Anatolia, held today by millions of Turkish and Kurdish Alevis in Turkey and its diaspora, with Qizilbash and Bektashi historical roots. It centers on the unity Hak-Muhammed-Ali and the Twelve Imams, and on the claim that the inner meaning (batin) of religion outranks the outward law — God is sought face-to-face in the human being and the assembly, not in the mosque.",
  "cosmos": "Reality emanates from Hak (God/Truth), and the human being is its fullest mirror; the path aims at the perfected human (insan-i kamil) through the Four Doors — law, path, gnosis, truth. The primordial Assembly of the Forty (Kirklar Cemi), where Muhammad joined the gathered saints as an equal, is the charter of the ritual world. Devriye poetry frames existence as a circle — the soul descends from God through creation and climbs back — while concrete afterlife imagery is held lightly and varies by community.",
  "practice": "The congregational rite is the cem, led by a dede of hereditary sacred lineage: men and women together, hymns (nefes/deyis) to the bağlama lute, the turning semah dance, a shared meal, and the public airing and reconciliation of disputes — those at odds may not join the rite. Musahiplik binds two couples in lifelong mutual responsibility; the twelve-day Muharram fast mourns Karbala; pilgrimage centers on the shrine of Hacı Bektaş Veli. Alevis historically faced Ottoman persecution and still contest official recognition in Turkey.",
  "canon": "The Buyruk compilations, the Makalat attributed to Hacı Bektaş Veli, the Velayetname, and a vast sung corpus — above all the nefes of poets such as Pir Sultan Abdal and Shah Ismail (Hatayi); transmission is substantially oral.",
  "reflects": "The location of the sacred in the gathered community — worship as assembly, music, and reconciliation, with esoteric inwardness set deliberately against legalist orthodoxy.",
  "sources": [
   "David Shankland, 'The Alevis in Turkey' (2003)",
   "John Kingsley Birge, 'The Bektashi Order of Dervishes' (1937)",
   "Krisztina Kehl-Bodrogi, 'Die Kizilbaş/Aleviten' (1988)"
  ],
  "flagged": [
   "Population-share estimates for Alevis in Turkey (commonly 10–20%) are politically contested and unverifiable; no figure is asserted in the dossier body."
  ]
 },
 "amazonian": {
  "essence": "A composite shard: the visionary-shamanic religions of Amazonian peoples — here chiefly the Yanomami, Shipibo-Conibo, Tukano, and Gê — which share no single doctrine but a strong family resemblance: a cosmos of person-like beings in many bodies, negotiated by shamans in ecstatic states, often opened by psychoactive plants (ayahuasca, yakoana/ebene snuff). These are living traditions under acute pressure from extraction economies and missionization.",
  "cosmos": "The cosmos is layered and unstable — in Yanomami teaching the sky has fallen before and is held up now by shamans and their xapiri spirit-allies. Animals, plants, and rivers are 'people' from their own side (the perspectivism Viveiros de Castro systematized): each species has interiority, society, and a master who must be dealt with. Death disperses the person's soul-components; among the Yanomami the dead are mourned in reahu feasts in which the cremated remains are consumed and the dead's traces erased, releasing the living.",
  "practice": "The shaman is the central specialist, formed by apprenticeship, dietary restriction, and repeated visionary training; the work includes curing (extracting intrusions, recovering souls), negotiating game and weather, and defense against sorcery. Tukanoan and Arawakan peoples maintain the Yuruparí men's initiation cult, whose sacred flutes are forbidden to women's sight; Shipibo healers sing icaros understood as the audible form of the designs (kené) that pattern reality. Hunting itself is hedged with etiquette owed to the masters of animals.",
  "canon": "Oral corpora — chants, icaros, and myth cycles; landmark documentations include Reichel-Dolmatoff's Tukano cosmology and Davi Kopenawa's first-person Yanomami testimony 'The Falling Sky' (2013).",
  "reflects": "The cosmos as ongoing diplomatic work — religion as visionary negotiation among species and worlds, with the shaman as ambassador rather than priest.",
  "sources": [
   "Davi Kopenawa & Bruce Albert, 'The Falling Sky' (2013)",
   "Gerardo Reichel-Dolmatoff, 'Amazonian Cosmos' (1971)",
   "Eduardo Viveiros de Castro, 'Cannibal Metaphysics' (2009)",
   "Stephen Hugh-Jones, 'The Palm and the Pleiades' (1979)"
  ],
  "flagged": [
   "This is an analytic grouping across unrelated language families, not a single religion; generalizations (layered cosmos, soul-components) vary in detail by people."
  ]
 },
 "andean-pre-inca": {
  "essence": "The ceremonial religions of the pre-Inca Andes, known only archaeologically — chiefly Chavín de Huántar (c. 1200–500 BCE), the Moche of the north coast (c. 100–800 CE), and Tiwanaku on the altiplano (c. 500–1000 CE). No texts survive; what is attested is monumental: oracle galleries, sacrifice iconography, and the Staff God image that runs through the sequence toward the Inca Viracocha.",
  "cosmos": "Cosmology must be inferred from stone and ceramic: recurrent fanged anthropomorphs fusing human, feline, raptor, and serpent; the Staff God's rigid bilateral symmetry; dual, complementary organization visible in site planning. Moche art makes one principle explicit — captive blood feeds fertility and rain — while mountain, water, and Spondylus-shell offerings tie the whole sequence to a hydraulic sacred economy. Rich tombs (Sipán, the Lady of Cao) show the dead outfitted for continuing power.",
  "practice": "Chavín staged engineered revelation: pilgrims moved through lightless galleries toward the Lanzón oracle under San Pedro cactus, the architecture and acoustics producing controlled awe; snuff paraphernalia at Tiwanaku shows the entheogenic thread continuing. Moche practice centered on ritual combat, the sacrifice of captives, and the presentation of blood goblets — a ceremony whose priest and priestess roles match excavated burials. Tiwanaku added mass pilgrimage feasting with maize beer in monumental plazas.",
  "canon": "None — an unwritten tradition whose 'texts' are monuments and images: the Lanzón and Raimondi Stele, Moche fineline ceramics and the Huaca de la Luna murals, the Gateway of the Sun.",
  "reflects": "Religion as staged experience — the sacred produced through architecture, sensory manipulation, and spectacle, recoverable now only through its instruments.",
  "sources": [
   "Richard L. Burger, 'Chavín and the Origins of Andean Civilization' (1992)",
   "Christopher B. Donnan, 'Moche Art and Iconography' (1976)",
   "John Wayne Janusek, 'Ancient Tiwanaku' (2008)"
  ],
  "flagged": [
   "All doctrine here is inference from material remains — intentionally minimal claims.",
   "The tradition record's auto-dated period (-1200 to -700) covers only Chavín's florescence; Moche and Tiwanaku extend the shard to c. 1000 CE."
  ]
 },
 "andean": {
  "essence": "The imperial religion of the Inca state (Tawantinsuyu, c. 1400–1533) laid over a far older Andean substrate of huaca worship shared by Quechua- and Aymara-speaking peoples. Its core: a sacred landscape of person-like powers — Sun, Thunder, Earth, mountains, springs, ancestors — bound to humans by strict reciprocity, with the Sapa Inca ruling as the Sun's own descendant.",
  "cosmos": "The world divides into hanan pacha (the upper world), kay pacha (this world), and uku pacha (the inner world), crossed by flows of water and of camaquen, the animating force that makes each thing what it is. Creation is credited to Viracocha, who emerged at Lake Titicaca, but the working cosmos runs on feeding: rain, fertility, and order are repaid with chicha, coca, textiles, and blood. The honored dead were not sent away but kept — as mummies (mallki) they remained present, fed, and consulted, the royal mummies still holding court in Cusco.",
  "practice": "A professional priesthood served the state cult of Inti at the Qorikancha in Cusco, with chosen women (aqllakuna) brewing and weaving for the gods; from that center radiated the ceque lines organizing hundreds of shrines. Regular rites offered llamas, chicha, and cloth; at moments of crisis the state performed capacocha, the sacrifice of children on high peaks. Festivals such as Inti Raymi fixed the ritual year, while local communities maintained — and in folk-Catholic form still maintain — their own huacas and Pachamama offerings.",
  "canon": "No writing: khipu knotted cords carried record-keeping; the myths survive through early colonial texts — above all the Quechua-language Huarochirí Manuscript (c. 1608) and the Spanish chronicles (Betanzos, Sarmiento de Gamboa, Cobo).",
  "reflects": "Reciprocity as cosmic law — religion as the feeding of a living landscape and a living dead, fused seamlessly with state power.",
  "sources": [
   "Frank Salomon & George L. Urioste (trans.), 'The Huarochirí Manuscript' (1991)",
   "Sabine MacCormack, 'Religion in the Andes' (1991)",
   "Brian S. Bauer, 'The Sacred Landscape of the Inca: The Cusco Ceque System' (1998)",
   "Bernabé Cobo, 'Inca Religion and Customs' (1653)"
  ]
 },
 "anito": {
  "essence": "The indigenous religion of the Philippine archipelago before and beneath Spanish Catholicism — a family of Austronesian animisms (Tagalog, Visayan, and many others) rather than one church. Its shared core: the world is thick with anito/diwata — ancestral and nature spirits — approached through offerings and through the babaylan or katalonan, the typically female (or feminized-male, asog) spirit-medium.",
  "cosmos": "Cosmologies are layered — skyworld, earth, and underworld(s) — with a remote supreme figure (Tagalog Bathala, whose title derives from Sanskrit via Indic trade contact) above a crowd of transactional local spirits. Illness is commonly read as soul-loss or spirit offense demanding restitution, and several groups reckon the person as carrying more than one soul-component. At death the soul journeys to a spirit-land (Visayan Sulad among others), in some accounts ferried across water; ancestors properly honored become anito who guard their descendants.",
  "practice": "The central rite is the pag-anito: an offering-seance in which the babaylan feasts, chants, and enters trance to host the spirit, negotiating cures, harvests, and safe voyages; animal sacrifice (pig, chicken) and food offerings are standard. Households kept carved spirit-figures (taotao/larauan), and rites marked planting, fishing, birth, and death. Under Spanish rule babaylan practice was suppressed and folded into folk-Catholic forms, where much of it persists.",
  "canon": "An oral corpus of myth, epic, and ritual chant; the earliest written documentation is Spanish-colonial — the Boxer Codex (c. 1590), the relations of Plasencia (1589) and Loarca (1582), and Alcina's Visayan history (1668).",
  "reflects": "Transactional animism under feminine ritual authority — the sacred as a crowd of touchy neighbors managed through etiquette, offerings, and trance.",
  "sources": [
   "William Henry Scott, 'Barangay: Sixteenth-Century Philippine Culture and Society' (1994)",
   "Francisco Ignacio Alcina, 'Historia de las islas e indios de Bisayas' (1668)",
   "F. Landa Jocano, 'Outline of Philippine Mythology' (1969)"
  ],
  "flagged": [
   "Neat pan-Philippine pantheon lists in secondary literature over-systematize scattered colonial sources; deity rosters and afterlife names vary sharply by ethnolinguistic group."
  ]
 },
 "anthroposophy": {
  "essence": "The 'spiritual science' of Rudolf Steiner (1861–1925), who broke from the Theosophical Society and constituted the Anthroposophical Society in 1912/13, headquartered at the Goetheanum in Dornach, Switzerland. It claims that a rigorously trained 'exact clairvoyance' can investigate spiritual worlds as methodically as natural science investigates matter; its institutional offspring — Waldorf schools, biodynamic agriculture, anthroposophical medicine — far outreach its formal membership.",
  "cosmos": "Cosmos and humanity evolve together through vast planetary stages and cultural epochs (including Lemuria and Atlantis, which Steiner claimed to read from the Akashic record); the human being is fourfold — physical, etheric, and astral bodies crowned by the 'I' — and develops through reincarnation under karma. The incarnation and death of Christ, the 'Mystery of Golgotha,' is held to be the objective turning point of evolution, with Christ now active in the Earth's etheric sphere between the polar temptations of Lucifer (ungrounded spiritualization) and Ahriman (mechanizing materialism). After death the soul passes through purgation and spiritual regions before returning to a new incarnation.",
  "practice": "Practice is cognitive and meditative rather than congregational: concentration and meditation exercises, study, and the arts (eurythmy, speech formation), with an inner School of Spiritual Science for committed members. Its distinctive liturgy is applied work — pedagogy, farming, and medicine run as spiritual disciplines. The Christian Community, a sacramental church founded in 1922 with Steiner's help, stands adjacent but organizationally distinct.",
  "canon": "Steiner's written books — 'The Philosophy of Freedom' (1894), 'Theosophy' (1904), 'How to Know Higher Worlds' (1904–05), 'An Outline of Esoteric Science' (1910) — plus roughly 6,000 transcribed lectures in a collected edition of some 350 volumes.",
  "reflects": "The drive to make esoteric knowledge respectable as science — revelation recast as method, and spirituality validated through worldly institutions.",
  "sources": [
   "Helmut Zander, 'Anthroposophie in Deutschland' (2007)",
   "Olav Hammer, 'Claiming Knowledge: Strategies of Epistemology from Theosophy to the New Age' (2001)",
   "Geoffrey Ahern, 'Sun at Midnight: The Rudolf Steiner Movement and Gnosis in the West' (1984)"
  ]
 },
 "arabian": {
  "essence": "The polytheisms of the Arabian Peninsula before Islam — the tribal cults of the north and center (Mecca's Hubal, al-Lat, al-Uzza, and Manat, with Allah as high creator), the temple-states of South Arabia (Saba's national moon-god Almaqah and kin), and Nabataean Petra (Dushara). As public religion it ended with the destruction of the Kaaba idols in 630 CE, surviving as substrate within Islam and in tens of thousands of inscriptions.",
  "cosmos": "No systematic native cosmology survives; what is attested is a high creator invoked in extremity but approached through intercessor deities, prominent astral worship in the south, and a world shared with jinn. Pre-Islamic poetry is strikingly fatalistic — dahr, impersonal Time, devours all — and evidence for afterlife hope is thin; the Qur'an's own polemic records Meccan denial of resurrection. Fate-goddesses such as Manat personified the allotted term of life.",
  "practice": "Cult centered on sanctuaries (haram) with sacred stones (betyls) as often as images: pilgrimage, circumambulation, animal sacrifice, votive offerings, and divination by arrows before Hubal, while seers (kahins) delivered oracles in rhymed prose. Sacred truce months made pilgrimage and markets possible across tribal war; South Arabian temples ran formal economies with dedications, tithes, and ritual hunts.",
  "canon": "No scripture: the sources are epigraphy (Safaitic, Sabaic, Nabataean), pre-Islamic poetry, the Qur'an's polemic, and later Islamic antiquarianism — above all Ibn al-Kalbi's 'Book of Idols' (early 9th century).",
  "reflects": "The aniconic sacred center — stone, sanctuary, truce, and pilgrimage as religion's skeleton — preserved chiefly through the polemic of the tradition that replaced it.",
  "sources": [
   "Robert G. Hoyland, 'Arabia and the Arabs' (2001)",
   "G. R. Hawting, 'The Idea of Idolatry and the Emergence of Islam' (1999)",
   "Ahmad Al-Jallad, 'The Religion and Rituals of the Nomads of Pre-Islamic Arabia' (2022)",
   "Ibn al-Kalbi, 'Kitab al-Asnam (Book of Idols)' (early 9th c.)"
  ],
  "flagged": [
   "The Meccan picture rests heavily on Islamic-era sources written after the fact (Ibn al-Kalbi, the Sira); recent epigraphic work (Al-Jallad) revises older generalizations such as a uniform South Arabian 'astral triad.'"
  ]
 },
 "ascended-masters": {
  "essence": "A twentieth-century American esoteric family descending from Theosophy: the I AM Activity founded by Guy and Edna Ballard after Guy's claimed 1930 encounter with Saint Germain on Mount Shasta, continued by the Bridge to Freedom (1951) and by Mark and Elizabeth Clare Prophet's Summit Lighthouse / Church Universal and Triumphant (1958). It claims that perfected former humans — Ascended Masters organized as the Great White Brotherhood — actively govern Earth's spiritual evolution and speak through accredited Messengers.",
  "cosmos": "Above each person hovers an individualized 'Mighty I AM Presence,' a personal focus of God connected to the heart, while the soul evolves through reincarnation under karma. The goal is the ascension: balancing one's karma and reuniting with the I AM Presence, permanently exiting rebirth as the Masters are held to have done. Cosmic administration runs through the Seven Rays and their Chohans, with figures like Sanat Kumara holding planetary office and the Aquarian Age assigned to Saint Germain.",
  "practice": "The signature practice is decreeing — rapid, rhythmic spoken invocations directing divine energy — especially calls to the Violet Flame to transmute karma and the daily Tube of Light for psychic protection. Adherents study the Masters' dictations delivered through the movements' Messengers; the I AM Activity added patriotic ritual and strict abstinences, and the Church Universal and Triumphant built a communal Montana headquarters, drawing national attention with its 1990 fallout-shelter mobilization.",
  "canon": "Guy Ballard's 'Unveiled Mysteries' (1934), 'The Magic Presence' (1935), and 'The I AM Discourses' (1935); the Prophets' 'Climb the Highest Mountain' (1972) and thousands of published dictations — all atop the Theosophical substrate of Blavatsky and Bailey.",
  "reflects": "Grace mechanized and democratized — esoteric hierarchy turned into an accessible spiritual technology of spoken command, saturated with American optimism about self-improvement.",
  "sources": [
   "Charles S. Braden, 'These Also Believe' (1949)",
   "Bradley C. Whitsel, 'The Church Universal and Triumphant: Elizabeth Clare Prophet's Apocalyptic Movement' (2003)",
   "Catherine Wessinger, 'How the Millennium Comes Violently' (2000)"
  ]
 },
 "ayyavazhi": {
  "essence": "A monotheistic South Indian movement born among the oppressed Nadar caste of the Kanyakumari region (then southern Travancore), centered on Ayya Vaikundar (c. 1809-1851), whom followers hold to be the incarnation of the supreme Ekam, emerging from the sea at Thiruchendur in 1833 by the tradition's account. It claims the present dark age and its caste hierarchy are the final manifestation of primordial evil, and that Vaikundar's advent begins their overthrow. Officially enumerated within Hinduism, it maintains its own scripture, worship centers, and festival calendar.",
  "cosmos": "The Akilam reworks Puranic yuga cosmology: the primordial evil Kroni is fragmented across successive ages, his pieces incarnating as the villains of each yuga, culminating in Kaliyan, whose rule manifests concretely as caste oppression and colonial power. Vaikundar's mission closes the Kali Yuga and inaugurates Dharma Yukam, a permanent earthly age of equality over which he rules — a linear exit from the cycle rather than another turn of it. At the end Vaikundar judges all; Kroni's final fragment is destroyed, and the Santror — the marginalized recast as noble lineage — inherit the renewed earth.",
  "practice": "Worship occurs at the head temple at Swamithope and at hundreds of Nizhal Thangals — plain halls without images, where a lamp and mirror replace the murti and no priestly caste mediates. Characteristic acts include recitation of the Akilam, communal bathing rooted in the anti-caste defiance of the Muthiri Kinaru well, and festivals marking Vaikundar's 1833 advent; the 1836 Thuvayal Thavasu mass penance is remembered as the founding communal discipline. Ethics center on caste equality and the refusal of ritual mediation.",
  "canon": "The Akilathirattu Ammanai ('Akilam'), by tradition dictated to and written down by Hari Gopalan Citar from 1841, is the primary scripture; the Arul Nool is the secondary collection.",
  "reflects": "It foregrounds the religious impulse to overturn social hierarchy — eschatology as the vindication of the oppressed, with the outcaste recast as the cosmos's chosen heir.",
  "sources": [
   "G. Patrick, 'Religion and Subaltern Agency: A Case-study of Ayya Vali' (2003)",
   "R. Ponnu, 'Sri Vaikunda Swamigal and the Struggle for Social Equality in South India' (2000)",
   "Samuel Mateer, 'The Land of Charity: A Descriptive Account of Travancore and Its People' (1871)"
  ],
  "flagged": [
   "Akilam authorship/date (Hari Gopalan Citar, 1841) is the tradition's own account, stated as such",
   "Census classification of Ayyavazhi adherents as Hindus is widely reported but not verified against census documents here",
   "Individual (interim) afterlife doctrine is not summarized because I could not confirm a standardized teaching; the Akilam's emphasis is collective eschatology"
  ]
 },
 "aztec": {
  "essence": "The state religion of the Mexica of Tenochtitlan and, more broadly, of Nahuatl-speaking central Mexico in the Late Postclassic (14th to early 16th centuries CE), destroyed as a public cult by the Spanish conquest of 1521. It bound a large pantheon — Huitzilopochtli, Tezcatlipoca, Tlaloc, Quetzalcoatl — to one central claim: the cosmos is fragile and must be fed, human blood and hearts repaying the gods' primordial self-sacrifice to keep the Fifth Sun moving.",
  "cosmos": "Reality has passed through five world-ages ('Suns'), the previous four each destroyed; the present Fifth Sun was born at Teotihuacan from the god Nanahuatzin's self-immolation and is fated to end in earthquakes. The layered cosmos — conventionally thirteen heavens above and nine underworld strata below — is pervaded by teotl, a single dynamic sacred energy of which the gods are concentrated manifestations. Afterlife destination followed manner of death rather than morality: warriors and sacrificial victims joined the sun, the drowned went to Tlaloc's verdant Tlalocan, and most of the dead made a grueling four-year descent to Mictlan ending in dissolution.",
  "practice": "A professional priesthood served temple precincts such as Tenochtitlan's Templo Mayor, coordinating the 365-day solar count and the 260-day divinatory count (tonalpohualli) into a festival round of eighteen monthly feasts. Rites included human sacrifice framed as nextlahualli ('debt-payment'), pervasive autosacrificial bloodletting, deity-impersonation (ixiptla), and warfare partly organized to supply captives. Commoners participated through household ritual, calendrical naming and divination, and the feast cycle.",
  "canon": "No scripture in the textual sense: pre-Columbian pictorial codices (the Codex Borgia group among others) plus post-conquest transcriptions of Nahua oral tradition — above all Sahagun's Florentine Codex (1577), the Leyenda de los Soles (1558), and the Annals of Cuauhtitlan.",
  "reflects": "It foregrounds reciprocity pushed to its limit — religion as the literal metabolic maintenance of the cosmos, with humanity cast as permanent debtor.",
  "sources": [
   "Bernardino de Sahagun, 'Florentine Codex: General History of the Things of New Spain' (1577)",
   "Inga Clendinnen, 'Aztecs: An Interpretation' (1991)",
   "James Maffie, 'Aztec Philosophy: Understanding a World in Motion' (2014)",
   "David Carrasco, 'City of Sacrifice: The Aztec Empire and the Role of Violence in Civilization' (1999)"
  ],
  "flagged": [
   "The thirteen-heavens/nine-underworlds count is the conventional schema; colonial sources vary on exact numbering"
  ]
 },
 "baganda": {
  "essence": "The traditional religion of the Baganda, the Bantu-speaking people of the Buganda kingdom on the northwestern shore of Lake Victoria in Uganda. It centers on a withdrawn creator, Katonda; a pantheon of national gods (balubaale) such as Mukasa and Kibuuka served by temples and mediums; ubiquitous ancestral spirits (mizimu); and the sacral kingship of the Kabaka, which binds clans, land, and spirits into one polity. Christianity and Islam displaced the public cult from the late 19th century, though ancestor practice and shrine mediumship persist.",
  "cosmos": "Katonda made the world and the first man, Kintu; in the foundational myth Kintu's wife Nnambi, returning to heaven for forgotten millet, is followed down by her brother Walumbe — Death — who has taken humans ever since. There is no elaborated heaven or hell: the dead remain nearby as mizimu, active in family affairs and dangerous until settled by rite, with the jawbone treated as the seat of a person's continuing presence. Several balubaale are remembered as once-human heroes elevated after death, so the line between god and ancestor is thin.",
  "practice": "Each lubaale had shrines with hereditary priests and spirit-mediums who delivered oracles in possession; offerings and, for some gods, blood sacrifice maintained the cults, while Katonda himself received almost no organized cult beyond simple household prayer. Royal religion centered on the masiro tombs — Kasubi above all — where mediums channeled deceased Kabakas, and on twin-rites associated with Mukasa. Clan (kika) membership assigned totems, ritual duties, and marriage rules; family heads managed the propitiation of the mizimu.",
  "canon": "An oral corpus — the Kintu and Walumbe cycle, clan and dynastic histories — first systematically written down by the Ganda statesman Apolo Kaggwa and the missionary-ethnographer John Roscoe in the early 20th century.",
  "reflects": "It foregrounds the fusion of polity and cult — kingship, clan, and ancestry forming one continuous administrative order that death does not interrupt.",
  "sources": [
   "John Roscoe, 'The Baganda: An Account of Their Native Customs and Beliefs' (1911)",
   "Benjamin C. Ray, 'Myth, Ritual, and Kingship in Buganda' (1991)",
   "Apolo Kaggwa, 'The Customs of the Baganda' (1934, English translation)"
  ]
 },
 "bahai": {
  "essence": "A global monotheistic religion founded by Baha'u'llah (Mirza Husayn-'Ali Nuri, 1817-1892), a Persian noble exiled from Iran to Baghdad — where in 1863 he declared himself the messianic figure foretold by the Bab (executed 1850) — then to Adrianople and the Ottoman prison-city of Akka. Its several million adherents span nearly every country; the central claims are the oneness of God, the progressive oneness of all revealed religion, and the oneness of humankind, with Baha'u'llah as the Manifestation of God for this age.",
  "cosmos": "God's essence is held to be absolutely unknowable; creation is held to have no beginning in time and is known through a succession of Manifestations — Abraham, Moses, Krishna, Buddha, Zoroaster, Christ, Muhammad, the Bab, Baha'u'llah — who mirror divine attributes without incarnating the divine essence. The rational soul comes into being with the body but is immortal; after death it progresses through spiritual worlds, with heaven and hell read as nearness to or remoteness from God rather than places. History is teleological: humanity is maturing toward a unified planetary civilization, the Most Great Peace.",
  "practice": "There is no clergy: practice rests on daily obligatory prayer (one of three prescribed forms), an annual nineteen-day sunrise-to-sunset fast preceding the Naw-Ruz new year, and monthly Nineteen Day Feasts combining worship, consultation, and fellowship. Community affairs are administered by elected councils — local and national Spiritual Assemblies under the Universal House of Justice, first elected in 1963 and seated in Haifa. Moral law includes monogamy, abstention from alcohol and from partisan politics, the wealth-purification payment Huququ'llah, and pilgrimage to the shrines at Bahji and Haifa.",
  "canon": "The writings of the Bab, Baha'u'llah (notably the Kitab-i-Aqdas and Kitab-i-Iqan), and 'Abdu'l-Baha constitute scripture, with Shoghi Effendi's interpretations and Universal House of Justice legislation completing the authoritative corpus.",
  "reflects": "It foregrounds the unification impulse — religion engineered to reconcile prior revelations into one progressive sequence and to make schism institutionally impossible.",
  "sources": [
   "Peter Smith, 'An Introduction to the Baha'i Faith' (2008)",
   "Shoghi Effendi, 'God Passes By' (1944)",
   "Moojan Momen, 'The Babi and Baha'i Religions, 1844-1944: Some Contemporary Western Accounts' (1981)"
  ],
  "flagged": [
   "Adherent figure stated loosely as 'several million'; published estimates commonly range about 5-8 million"
  ]
 },
 "balinese-hindu": {
  "essence": "The religion of the great majority of Bali's population — the Indonesian archipelago's Hindu remnant — formed from Shaiva Siddhanta and Buddhist currents carried from Java (reinforced when Majapahit's 15th-16th-century decline pushed Javanese Hindu elites to Bali) and fused with indigenous ancestor cult and spirit belief. Its modern form, Agama Hindu Dharma, was codified in the late 1950s and 1960s under the Parisada Hindu Dharma to satisfy the Indonesian state's requirement that a recognized religion profess one supreme God — hence the elevation of Sang Hyang Widhi Wasa (Acintya).",
  "cosmos": "The cosmos is a continuum of seen (sekala) and unseen (niskala) realms, spatially ordered along the kaja-kelod axis running from the mountains — the abode of gods, above all Gunung Agung — down to the sea, haunt of demonic forces (bhuta kala), with human space between. Opposed forces are permanent and complementary (rwa bhineda): ritual aims at balance, never the annihilation of the demonic. At death the soul is freed by cremation (ngaben) for purification and reincarnation, and is eventually enshrined as a deified ancestor in the family temple; karma and rebirth frame the cycle.",
  "practice": "Practice is relentlessly ritual and local: daily canang sari offerings; a dense temple network (every village classically holds the kahyangan tiga — temples of origin, of the community, and of the dead) with anniversary festivals each 210-day pawukon cycle; and life-cycle rites from birth through tooth-filing to cremation. Brahmana high priests (pedanda) prepare holy water while village temple priests (pemangku) serve the daily cult; subak irrigation associations tie water temples to rice ecology; the whole island halts annually for Nyepi, the day of silence. The stated ethic is Tri Hita Karana — harmony with God, among humans, and with nature.",
  "canon": "No single scripture governs practice: the working corpus is palm-leaf lontar manuscripts in Old Javanese and Balinese (theological texts such as the Bhuwana Kosa, plus ritual and architectural manuals), with the Vedas honored largely at a distance and the kakawin Ramayana and Mahabharata supplying the narrative frame.",
  "reflects": "It foregrounds religion as the aesthetic and spatial ordering of an entire landscape — belief enacted as perpetual offering, orientation, and balance rather than as creed.",
  "sources": [
   "Clifford Geertz, 'Negara: The Theatre State in Nineteenth-Century Bali' (1980)",
   "J. Stephen Lansing, 'Priests and Programmers: Technologies of Power in the Engineered Landscape of Bali' (1991)",
   "Michel Picard, 'Bali: Cultural Tourism and Touristic Culture' (1996)"
  ],
  "flagged": [
   "Codification chronology (state recognition and Parisada formation, late 1950s) stated from secondary literature, not primary Indonesian documents"
  ]
 },
 "baltic": {
  "essence": "The pre-Christian religion of the Baltic-speaking peoples — Lithuanians, Latvians, and the extinct Old Prussians — of the eastern Baltic littoral, among the most conservative descendants of common Indo-European religion. Lithuania, the last pagan state in Europe, formally converted only in 1387 (Samogitia in 1413), and folk practice carried the old gods in song into the modern era; the tradition has been consciously revived as Lithuanian Romuva and Latvian Dievturiba.",
  "cosmos": "A bright sky-order — Dievas the sky-god, Perkunas the thunderer, Saule the sun-mother driving her chariot — stands over Zemyna's earth and against the chthonic Velnias, lord of the dead, cattle, and waters, whom Perkunas eternally pursues; the marriage of Sun and Moon, and the Moon's infidelity with the dawn-star Ausrine, account for the lunar phases. Fate is allotted at birth by Laima, and even the gods defer to the portion she speaks. The dead (veles) pass into a community of souls that remains in relation with the living, commemorated at autumn feasts of the dead.",
  "practice": "Cult was largely open-air and domestic: sacred groves (alkai), holy fires, springs, and stones rather than temple institutions; households honored Zemyna with the first of bread and drink poured to the ground, and the year turned on solstice and harvest festivals (Rasos/Jani at midsummer) and commemorations of the dead (Lithuanian Velines). Medieval chronicles report organized sanctuaries and priesthoods, but those accounts are late, external, and contested; the reliable picture is a peasant religion of field, hearth, and season.",
  "canon": "No native scriptures: the corpus is oral — above all the enormous Latvian daina collections (Krisjanis Barons' 'Latvju dainas', 1894-1915) and Lithuanian folksong, read alongside hostile medieval chronicles and comparative Indo-European reconstruction.",
  "reflects": "It foregrounds sheer conservatism — the shard where Indo-European religion survived longest in living speech, its gods preserved as household words and folksong rather than doctrine.",
  "sources": [
   "Marija Gimbutas, 'The Balts' (1963)",
   "Algirdas Julien Greimas, 'Of Gods and Men: Studies in Lithuanian Mythology' (1992, English translation)",
   "Endre Bojtar, 'Foreword to the Past: A Cultural History of the Baltic People' (1999)"
  ],
  "flagged": [
   "Medieval reports of institutional sanctuaries and priesthoods (e.g., the 'Romuva' sanctuary in Peter of Dusburg's 1326 chronicle) are treated by scholars as unverifiable or embellished — presented here as contested"
  ]
 },
 "bambara": {
  "essence": "The traditional religion of the Bamana (Bambara), the Mande-speaking agriculturalists who form Mali's largest ethnic group, historically centered on the middle Niger around Segou. It combines a withdrawn creator (Maa Ngala / Ngala / Bemba), a cosmogony of rival twin powers (Faro and Pemba), an impersonal vital energy (nyama) released by speech, blood, and craft, and a ladder of initiation societies (jow) that dispense esoteric knowledge by degrees. Most Bamana today are Muslim; the jow, boliw altars, and masquerades persist unevenly alongside and beneath Islam.",
  "cosmos": "In the cosmogony recorded by Dieterlen, creation issues from primordial vibration and speech — the creator speaks the world's elements into being — after which the ambitious earth-twin Pemba descends and corrupts the order, and the androgynous water-twin Faro re-balances it, laying down the Niger, the seasons, and social law. All things carry nyama, an amoral energy concentrated by killing, iron-smelting, potent words, and oath-breaking; the cosmos is less governed than managed. The dead join the ancestors and remain parties to clan life, their power likewise a nyama matter requiring rite.",
  "practice": "Men pass through graded initiation societies — classically six: N'domo, Komo, Nama, Kono, Chi Wara, and Kore — each holding masks, altars, and knowledge disclosed only to initiates; the senior Komo, run exclusively by blacksmiths, polices sorcery and enforces communal order. Ritual technology centers on boliw, dense sacrificial power-objects fed with blood and organic matter, and on masquerades such as the Chi Wara antelope dances honoring farming labor. The endogamous specialist castes (nyamakala) — blacksmiths (numuw), bards, leatherworkers — handle the most dangerous concentrations of nyama.",
  "canon": "An oral and initiatic corpus — cosmogonic recitation, society liturgies, and esoteric sign-systems — with no scriptures; the principal written syntheses are 20th-century ethnographies (Dieterlen 1951; Zahan 1960; McNaughton 1988).",
  "reflects": "It foregrounds religion as power-management — the sacred as an amoral energy handled through graded secrecy, caste specialization, and engineered objects rather than worshiped as a person.",
  "sources": [
   "Germaine Dieterlen, 'Essai sur la religion bambara' (1951)",
   "Dominique Zahan, 'Societes d'initiation bambara: le N'domo, le Kore' (1960)",
   "Patrick R. McNaughton, 'The Mande Blacksmiths: Knowledge, Power, and Art in West Africa' (1988)",
   "Sarah C. Brett-Smith, 'The Making of Bamana Sculpture: Creativity and Gender' (1994)"
  ],
  "flagged": [
   "Dieterlen's highly systematized cosmogony (the creative words, the Faro/Pemba cycle) belongs to the Griaule school, whose reconstructions later ethnographers have criticized as over-schematic; presented as her account, not as uncontested Bamana consensus",
   "The canonical list of six jow follows Zahan; the count and membership vary regionally"
  ]
 },
 "basque": {
  "essence": "The pre-Christian religion of the Basques, speakers of Europe's only surviving language isolate, in the western Pyrenees. No ancient text describes it; it is reconstructed from Aquitanian votive inscriptions of the Roman era and, above all, from folklore collected in the 19th-20th centuries (chiefly by Jose Miguel de Barandiaran), which preserves a system centered on the cave-dwelling sovereign goddess Mari, a landscape of reciprocal spirits, and a household-anchored cult of the dead. Christianization was slow and layered rather than a datable event.",
  "cosmos": "Orientation is chthonic rather than celestial: divinity dwells inside the earth — Mari in the high caves, crossing the sky between peaks as fire — and in the folk cosmology recorded by Barandiaran the sun and moon are daughters of the earth (Amalur) who return into her each night, making the underground the true otherworld. Storms brew from Mari's meetings with her serpent consort Sugaar, and her justice punishes the lie, the theft, and the boast. The dead remain attached to the house (etxe), receiving light and offerings; no developed heaven, hell, or judgment survives in the folk record.",
  "practice": "No priesthood is attested: practice was domestic and reciprocal — offerings of food left for the lamiak in exchange for their night-work, apotropaic emblems such as the eguzkilore (a dried sun-thistle) fixed on doors, and the mistress of the house (etxekoandre) officiating for the household dead, in later centuries with argizaiola wax-boards burned at family tombs. Legend remembers petition of Mari at her caves for weather and redress; the akelarre ('he-goat meadow') witch-gatherings prosecuted at Zugarramurdi (1609-1614) show older nocturnal assemblies as the Inquisition refracted them.",
  "canon": "None: the corpus is oral folklore — legends, house-rites, and place-traditions — collected principally in Barandiaran's Eusko-Folklore materials and synthesized in his 'Mitologia vasca' (1960).",
  "reflects": "It foregrounds sovereignty relocated — supreme power gendered female and housed in the earth, with religion practiced as neighborly reciprocity rather than temple cult.",
  "sources": [
   "Jose Miguel de Barandiaran, 'Mitologia vasca' (1960)",
   "Julio Caro Baroja, 'The World of the Witches' (1964, English translation)",
   "'Selected Writings of Jose Miguel de Barandiaran: Basque Prehistory and Ethnography' (2007)"
  ],
  "flagged": [
   "Sun and moon as daughters of Amalur is standard in modern syntheses of Barandiaran's material but not verified here against his primary texts (~85% confidence)",
   "Argizaiola tomb-boards are attested as Christian-era funerary practice; their continuity with pre-Christian dead-cult is inference",
   "The whole picture is reconstruction from late folklore — the project's own tradition record marks certainty as 'inferred', and the akelarre material is heavily distorted by Inquisition sources"
  ]
 },
 "berber": {
  "essence": "The indigenous religious stratum of the Amazigh (Berber) peoples of North Africa — attested from classical antiquity (Herodotus' Libyans, the oracle of Ammon at Siwa, the war-bull Gurzil in Corippus) and in Latin epigraphy (the Dii Mauri) — underlying successive Punic, Roman, Christian, and Islamic overlays. Modern Imazighen are Muslim, but pre-Islamic patterns persist as folk practice: rain-bride processions, offerings at springs and caves, and tomb-centered piety continuous in form with the veneration of Muslim saints.",
  "cosmos": "No systematic native cosmology survives; the attested pattern is a sacralized landscape — mountains, caves, springs — plus celestial cult (Herodotus reports Libyan sacrifice to sun and moon) and, above all, powerful ancestors. The dead do not depart: Herodotus describes the Nasamones sleeping on ancestral tombs to receive prophetic dreams, and monumental tumuli (bazinas) served as oracular and juridical sites. Even weather is personal and negotiable — the rain, Anzar, must be courted with a bride rather than merely petitioned.",
  "practice": "Practice was tribal and place-bound rather than centralized: oracle consultation (Siwa's Ammon answered through the movements of his idol as priests carried it), dream incubation at tombs, the carrying of the divine bull Gurzil into battle, and offerings at springs and caves. The best-documented living survival is the Tislit n Anzar rain-bride complex, in which an adorned effigy — in most modern versions a ladle-doll — is processed and 'married' to the rain during drought. Islamic-era marabout (saint-tomb) piety carries forward the older ancestral-tomb pattern.",
  "canon": "None native and textual: the sources are classical authors (Herodotus Book 4; Corippus' 'Iohannis', 6th century), Libyco-Berber and Latin inscriptions, funerary archaeology, and modern Maghrebi ethnography of surviving rites — an oral and epigraphic corpus.",
  "reflects": "It foregrounds substrate persistence — a religion of land and ancestors that outlasts every imported system by seeping into it.",
  "sources": [
   "Gabriel Camps, 'Berberes: aux marges de l'histoire' (1980)",
   "Emile Laoust, 'Mots et choses berberes' (1920)",
   "Henri Basset, 'Le culte des grottes au Maroc' (1920)",
   "Corippus, 'Iohannis' (6th c.)"
  ],
  "flagged": [
   "Continuity between pre-Islamic ancestor/tomb cult and Islamic saint veneration is a widely argued scholarly reading (Basset, Camps), not a demonstrable lineage — stated as continuity 'in form'",
   "Ifri's identification as a cave goddess (and any 'Africa' etymology) rests on thin epigraphic and onomastic evidence and is deliberately omitted from the main text"
  ]
 },
 "black-hebrew-israelites": {
  "essence": "A family of African-American religious movements, emerging from the late 19th century (Frank Cherry's congregation, conventionally dated 1886; William S. Crowdy's Church of God and Saints of Christ, 1896), holding that Black Americans — and in some branches other peoples of the Americas — are literal genealogical descendants of the biblical Israelites. The spectrum runs from Torah-observant congregations influenced by rabbinic Judaism (Wentworth A. Matthew's Commandment Keepers, founded in Harlem in 1919) to the militant '1 West' street camps descending from Abba Bivens' 1960s Israeli School; there is no unified organization or creed.",
  "cosmos": "The framework is biblical monotheism read as racialized covenant history: the Transatlantic slave trade is identified as fulfillment of the curses of Deuteronomy 28 — especially the slave ships of verse 68 — so that collective suffering itself proves Israelite identity. In the militant camps, modern peoples are mapped onto biblical lineages, Europeans identified with Edom as the adversary, and history moves toward a literal earthly Kingdom in which the returned messiah restores Israelite sovereignty and inverts the present racial order. Afterlife doctrine is comparatively thin; the weight falls on corporate destiny within history.",
  "practice": "Practice varies by camp: Sabbath-keeping, biblical feasts and dietary law, fringed garments, adoption of Hebrew names, and the pedagogy of 'waking up' — learning one's tribal identity from charts correlating modern ethnic groups with the Twelve Tribes. The street wing is defined by confrontational public exegesis — loud, chart-based sidewalk preaching and debate — while congregational wings maintain synagogue-style worship. Authority is local and charismatic: teachers, schools, and camps rather than a clerical hierarchy.",
  "canon": "The Bible — typically the King James Version with the Apocrypha (2 Esdras matters to several camps) — read through the movement's identity hermeneutic; no additional unified scripture.",
  "reflects": "It foregrounds chosenness as theodicy — collective suffering converted into forensic proof of election, with identity-recovery itself functioning as salvation.",
  "sources": [
   "Jacob S. Dorman, 'Chosen People: The Rise of American Black Israelite Religions' (2013)",
   "James E. Landing, 'Black Judaism: Story of an American Movement' (2002)",
   "John L. Jackson Jr., 'Thin Description: Ethnography and the African Hebrew Israelites of Jerusalem' (2013)"
  ],
  "flagged": [
   "Frank Cherry's 1886 founding date is conventional but weakly documented (Dorman questions the early chronology)",
   "The Edom doctrine and Kingdom-inversion eschatology describe the militant 1-West lineage specifically, not all Black Israelite congregations"
  ]
 },
 "bon": {
  "essence": "The Tibetan religion that understands itself as the pre-Buddhist faith of Tibet and the ancient kingdom of Zhangzhung, founded by the enlightened teacher Tonpa Shenrab of Olmo Lungring ages before Shakyamuni. Historically, organized Yungdrung ('Eternal') Bon is a systematization of roughly the 10th-14th centuries CE, developed in rivalry and deep mutual exchange with Tibetan Buddhism, while genuinely archaic strata — the three-tiered spirit world, the sky-cord kingship myth, the royal funerary cult — survive within and beneath it. It remains a living minority tradition among Tibetans, recognized in exile as a distinct school.",
  "cosmos": "The archaic stratum peoples a three-tiered world — bright lha above, touchy nyen in rock and middle air, serpentine klu in water and soil — where illness follows offense against the landscape's proprietors; the first kings descended from heaven on the mu-cord and left no corpses until the cord was cut, the myth of death's origin. Systematized Bon adds cosmic-egg cosmogonies hatching light and dark lineages, the nine-storeyed swastika mountain at the world's center, and a Buddhist-style economy of karma, rebirth, and liberation. At death the archaic rites ransom and guide the soul; the later tradition conducts the dead through an intermediate state toward rebirth or release.",
  "practice": "Yungdrung Bon is institutionally monastic — Menri monastery (founded 1405) headed the tradition — with a full curriculum of vows, philosophical study, tantric deity practice, and Dzogchen contemplation (the Zhangzhung Nyengyu lineage); practitioners circumambulate counterclockwise and turn the swastika leftward, mirror-reversing Buddhist convention. Village religion continues propitiation of local spirits, ransom rites, divination, and healing — the older gshen priestcraft. Pilgrimage centers on Mount Kailash (Tise) and Bonri.",
  "canon": "A large canon in Kangyur- and Tengyur-like collections, centered on the biographies of Tonpa Shenrab — the short mDo-'dus, the middle Zermig, and the twelve-volume gZi-brjid — much of it surfacing as rediscovered 'treasure' (terma) texts from the 10th century onward.",
  "reflects": "It foregrounds self-definition against a dominant rival — a tradition asserting priority over the system it structurally mirrors, while genuinely preserving fragments of the older religion beneath.",
  "sources": [
   "Samten G. Karmay, 'The Arrow and the Spindle: Studies in History, Myths, Rituals and Beliefs in Tibet' (1998)",
   "Per Kvaerne, 'The Bon Religion of Tibet: The Iconography of a Living Tradition' (1995)",
   "David L. Snellgrove, 'The Nine Ways of Bon' (1967)",
   "Namkhai Norbu, 'Drung, Deu and Bon: Narrations, Symbolic Languages and the Bon Tradition in Ancient Tibet' (1995)"
  ],
  "flagged": [
   "Menri's founding year (1405) and the gZi-brjid's medieval dating are stated from standard references, not primary verification",
   "The exile recognition of Bon as a fifth Tibetan school is real but its exact date (variously cited late 1970s) is deliberately omitted"
  ]
 },
 "brahmoism": {
  "essence": "Two linked 19th-century Indian reform movements that recast Hinduism as formless monotheism: the Brahmo Samaj, founded in Calcutta in 1828 by Rammohan Roy and institutionalized under Debendranath Tagore and Keshub Chandra Sen, and the Arya Samaj, founded in Bombay in 1875 by Dayananda Saraswati. Both reject image-worship, avatars, and priestly mediation; the Brahmos built a universalist, rationalist theism drawing on the Upanishads (and on Christian-Unitarian models), while the Arya Samaj preached restoration of an infallible Vedic revelation — 'back to the Vedas' — with missionary intent.",
  "cosmos": "Both affirm one formless, moral creator God and an immortal soul, against the Puranic pantheon. Arya doctrine (traitavada) holds God, souls, and material prakriti to be three beginningless eternals, retains karma, rebirth, and moksha, and treats the world as fully real against Advaita illusionism; Brahmo theology, less systematized, converged on ethical theism — God known through reason, conscience, and nature — with the Adi Brahmo stream formally dropping Vedic infallibility around 1850. Neither developed a distinctive new afterlife picture beyond these inherited frames.",
  "practice": "Congregational, Protestant-inflected worship replaced temple and image: weekly services of prayer, sermon, and hymn under trust-deed institutions (the Brahmo trust deed of 1830 barred images from the premises). The Arya Samaj democratized the Vedic fire rite (havan) as a daily lay duty, ran shuddhi purification to reconvert Muslims and Christians and to admit excluded castes to full Vedic participation, and built schools (the D.A.V. and gurukul networks); both movements campaigned against sati and child marriage and for widow remarriage and women's education.",
  "canon": "Brahmos read the Upanishads selectively alongside founders' writings (Roy's tracts; Debendranath's 'Brahmo Dharma', 1850) without holding any scripture infallible; the Arya Samaj holds the four Veda Samhitas alone infallible, with Dayananda's 'Satyarth Prakash' (1875) as doctrinal charter.",
  "reflects": "It foregrounds rationalizing reform under external pressure — a tradition re-engineering itself as creedal, congregational, and purified while claiming the deepest antiquity for the result.",
  "sources": [
   "David Kopf, 'The Brahmo Samaj and the Shaping of the Modern Indian Mind' (1979)",
   "Kenneth W. Jones, 'Arya Dharm: Hindu Consciousness in 19th-Century Punjab' (1976)",
   "J.T.F. Jordens, 'Dayananda Sarasvati: His Life and Ideas' (1978)"
  ],
  "flagged": [
   "'Around 1850' for the Brahmo abandonment of Vedic infallibility is approximate — the shift followed Debendranath's Benares inquiry of the late 1840s"
  ]
 },
 "buddhist-vehicles": {
  "essence": "Not a separate religion but Buddhism's three great self-descriptions of the path: Theravada, the surviving Nikaya school of Sri Lanka and Southeast Asia claiming the elders' lineage; Mahayana, the 'great vehicle' movement emerging around the beginning of the common era in India and dominant in East Asia; and Vajrayana, the tantric 'diamond vehicle' formalized from about the 7th century CE and carried into Tibet, Mongolia, the Himalayas, and Japan (Shingon). Each vehicle crystallizes a different ideal of the perfected person — the arahant who ends rebirth, the bodhisattva who postpones final release for the sake of all beings, the tantric adept who enacts buddhahood now.",
  "cosmos": "All three share the common Buddhist frame — beginningless samsara, karma, rebirth, and liberation — but weight it differently: Theravada analyzes experience into momentary dhammas with nibbana as the unconditioned; Mahayana universalizes emptiness (sunyata), the three buddha-bodies (trikaya), and, in one influential strand, an innate buddha-nature in all beings; Vajrayana treats the world, properly seen, as already a pure mandala, and elaborates death itself (the bardo literature) as an opportunity for liberation.",
  "practice": "Theravada practice centers on monastic discipline, merit-making, and insight meditation; Mahayana adds the bodhisattva vow and perfections, vast devotional cults (Amitabha's Pure Land, Avalokiteshvara), and scholastic philosophy; Vajrayana requires empowerment (abhisheka) from a qualified guru, then deity-yoga — visualizing oneself as the yidam with mantra and mudra — under strict samaya bonds, the lama elevated to embodiment of the Buddha. Historically the vehicles stack rather than exclude: Vajrayana presupposes Mahayana, which presupposes the shared discipline.",
  "canon": "The Pali Tipitaka for Theravada; the Mahayana sutras (Prajnaparamita, Lotus, the Tathagatagarbha corpus) preserved chiefly in the Chinese and Tibetan canons; and the tantras (Guhyasamaja, Hevajra) with their commentarial and lamrim literature for Vajrayana.",
  "reflects": "It foregrounds a tradition arguing with itself about the goal — perfection defined successively as escape, as compassionate return, and as transmutation of the present.",
  "sources": [
   "Paul Williams, 'Mahayana Buddhism: The Doctrinal Foundations' (2nd ed., 2009)",
   "Walpola Rahula, 'What the Buddha Taught' (1959)",
   "David Snellgrove, 'Indo-Tibetan Buddhism: Indian Buddhists and Their Tibetan Successors' (1987)"
  ]
 },
 "buddhist": {
  "essence": "The tradition founded on the teaching (dharma) of Siddhartha Gautama, the Buddha, active in the Gangetic plain in roughly the 5th century BCE (his death is placed c. 483 or c. 400 BCE on the long and short chronologies). Now numbering on the order of half a billion adherents across Asia and worldwide, it centrally claims that conditioned existence is unsatisfactory (dukkha), driven by craving and ignorance, and that liberation (nirvana) is attainable by the eightfold path — without recourse to a creator god or an eternal self.",
  "cosmos": "Each world-system is built around Mount Sumeru, heavens stacked above and hells below, and arises, endures, and dissolves across immense kalpas — beginninglessly, by the impersonal law of dependent origination, with no creator behind the process. Beings migrate through six realms of rebirth — gods, titans, humans, animals, hungry ghosts, hell-beings — according to karma; even the gods, Indra included, are impermanent inmates of the wheel. At death rebirth follows karma until awakening ends the cycle; the doctrine of anatman denies any eternal self that transmigrates — only a conditioned stream continues.",
  "practice": "The institutional core is the sangha, the monastic order governed by vinaya discipline and supported by lay donors in a merit economy; lay practice rests on the five precepts, giving (dana), and observance days (uposatha). Cultivation combines ethical discipline, meditation (calm and insight), and study; devotional life centers on stupas, relics, images, and pilgrimage. Forms vary enormously across the Theravada, Mahayana, and Vajrayana worlds, from austere forest monasticism to elaborate liturgical and tantric systems.",
  "canon": "The Pali Tipitaka is the complete surviving early canon; the Mahayana world transmits vast additional sutra and commentarial corpora in the Chinese canon and the Tibetan Kangyur/Tengyur, with cosmology systematized in Abhidharma works, above all Vasubandhu's Abhidharmakosa (4th-5th c. CE).",
  "reflects": "It foregrounds order without a lawgiver — the religious impulse toward total causal law, with salvation as seeing through the self rather than appealing to a maker.",
  "sources": [
   "Rupert Gethin, 'The Foundations of Buddhism' (1998)",
   "Akira Sadakata, 'Buddhist Cosmology: Philosophy and Origins' (1997)",
   "Vasubandhu, 'Abhidharmakosa' (4th-5th c. CE; trans. La Vallee Poussin / Pruden)"
  ]
 },
 "buryat": {
  "essence": "The shamanic religion of the Buryats, the Mongolic-speaking people of the Lake Baikal region (with communities in Mongolia and Inner Mongolia) and one of the largest indigenous peoples of Siberia. It is a Tengerist cosmology: a heaven of 99 tengri divided into 55 benevolent western ('white') and 44 hostile eastern ('black') gods above an inhabited middle world and Erlen Khan's underworld, mediated by hereditary shamans. From the 17th-18th centuries Tibetan (Gelug) Buddhism spread among eastern Buryats, producing deep syncretism; Soviet repression nearly destroyed both clergies, and a marked shamanic revival has followed since the 1990s.",
  "cosmos": "The world is vertically tiered — sky, earth, underworld — with Father Heaven complemented by Etugen Ekhe, the un-personified Mother Earth, and the heavens themselves a divided polity whose western and eastern factions war, mirroring steppe politics. Human fortune depends on standing with the tengri, with local master-spirits of mountains and waters, and with clan ancestors; the dead pass under Erlen Khan's ledger-keeping rule, while notable ancestors can be installed in ongon effigies as ongoing protectors. Illness and misfortune are read as spirit action — or as the shamanic call itself.",
  "practice": "Religion is clan-based and negotiated: communal tailgan sacrifices of sheep and horses with libations of milk and milk-spirits to the tengri and place-masters; the feeding of ongon effigies with fat and blood; offerings at sacred sites, above all Olkhon Island in Baikal. Shamans — male boo, female udagan, divided into white (celestial) and black (chthonic) service — are made, not self-selected: an inherited vocation manifests as the violent 'shamanic illness', and survivors are consecrated through staged initiations. Buddhist Buryats overlay this with lamaist ritual, and many practices are now shared.",
  "canon": "Oral: the great Buryat redactions of the Geser epic ('Abai Geser'), clan genealogies, and shamanic invocations, recorded by ethnographers from the 19th century onward (Khangalov, Curtin); Buddhist Buryats use the Tibetan canon.",
  "reflects": "It foregrounds the negotiated cosmos — religion as continuous diplomacy between human clans and a factional spirit-polity, conducted by conscripted specialists.",
  "sources": [
   "Roberte Hamayon, 'La chasse a l'ame: esquisse d'une theorie du chamanisme siberien' (1990)",
   "Caroline Humphrey, 'Karl Marx Collective: Economy, Society and Religion in a Siberian Collective Farm' (1983)",
   "Jeremiah Curtin, 'A Journey in Southern Siberia: The Mongols, Their Religion and Their Myths' (1909)"
  ],
  "flagged": [
   "'One of the largest indigenous peoples of Siberia' phrased deliberately — recent censuses put Sakha (Yakut) numbers slightly above Buryat, so 'largest' would over-claim"
  ]
 },
 "california-tribes": {
  "essence": "The indigenous religious complex of the Chumash of the Santa Barbara Channel coast and islands, with close parallels among neighboring southern-California peoples such as the Gabrielino/Tongva (whose toloache-centered Chinigchinich religion overlaps it). A dense maritime hunter-gatherer society, its religion turned on keeping balance with a powerful, ambivalent cosmos through an elite priesthood, solstice ritual, and the datura vision quest. Suppressed under the Spanish missions, it survives in the recorded oral corpus and an active Chumash cultural revival.",
  "cosmos": "Three flat worlds stack vertically: an Upper World of powerful Sky People — the Sun, Sky Coyote, the great eagle Slo'w — this Middle World, an island resting on two giant serpents whose stirrings cause earthquakes, and a dangerous Lower World of nunasis beings that emerge at night. Human fortune is not decreed but gambled: each winter solstice the Sky People play the hand-game peon, Sky Coyote against the Sun, and the outcome sets the coming year's rain, food, and deaths. At death the soul travels west to Humqaq (Point Conception) and crosses the sea to Similaqsa, the land of the dead.",
  "practice": "The 'antap, a closed society of ritualists and astronomer-priests drawn largely from chiefly families, ran the ceremonial calendar — above all the winter solstice rites — kept an esoteric ritual language, and stood at the center of political authority. Initiates, the sick, and mourners drank toloache, a decoction of datura personified as the grandmother Momoy, under specialist supervision to gain a dream helper. Autumn harvest festivals honored the earth deity Hutash, and shrines and painted rock-art sites marked a landscape read astronomically.",
  "canon": "An oral corpus with no native scripture: its principal record is the vast early-twentieth-century ethnographic archive John P. Harrington collected from Chumash consultants such as Fernando Librado and María Solares, edited in works like Blackburn's 'December's Child' (1975).",
  "reflects": "Religion as risk management before an amoral cosmos — the year's fate is literally a wager between sky powers, and ritual expertise is the margin humans buy against it.",
  "sources": [
   "Thomas C. Blackburn, 'December's Child: A Book of Chumash Oral Narratives' (1975)",
   "Travis Hudson & Ernest Underhay, 'Crystals in the Sky: An Intellectual Odyssey Involving Chumash Astronomy, Cosmology and Rock Art' (1978)",
   "A. L. Kroeber, 'Handbook of the Indians of California' (1925)"
  ],
  "flagged": [
   "The Rainbow Bridge (Wishtoyo) narrative is prominent in the modern Chumash revival; how fully it is attested in the early ethnographic record is less clear to me than the Harrington-derived material, so it is omitted from the dossier body.",
   "Details of 'antap organization and recruitment follow Hudson & Underhay's reconstruction, which is partly inferential."
  ]
 },
 "canaanite": {
  "essence": "The polytheism of the Bronze and Iron Age Levant — city-states such as Ugarit, Byblos, Tyre, and Sidon — carried west by Phoenician colonists and persisting in Punic Carthage until 146 BCE. Its pantheon, presided over by the patriarch El with the storm-god Ba'al Hadad as active king, is known chiefly from the cuneiform tablets excavated at Ras Shamra (ancient Ugarit) from 1929, and it forms the immediate religious background of the Hebrew Bible.",
  "cosmos": "Cosmic order is a contested kingship among the gods: under El's presidency, Ba'al wins rule by defeating Yam (Sea) and is swallowed by and returns from Mot (Death) — a combat cycle often read as mirroring the agricultural year. The dead descend to a shadowy underworld, Mot's realm; deceased kings join the rpum (Rephaim) and receive funerary offerings. The surviving texts show no developed doctrine of moral judgment after death.",
  "practice": "Temple-based animal sacrifice conducted by professional priesthoods, with the king as chief cultic patron; seasonal festivals, votive offerings, divination, and the marzihu, an aristocratic ritual drinking association attested at Ugarit. Royal ancestor cult is documented in the ritual tablets. In the Punic west, the tophet precincts of Carthage and its colonies received urns of cremated infants — whether these represent child sacrifice (as biblical and classical polemic charges) or a cemetery for those who died young remains a live scholarly debate.",
  "canon": "The Ugaritic tablets (fourteenth–twelfth centuries BCE): the Baal Cycle, the epics of Kirta and Aqhat, and an extensive ritual corpus — supplemented by Phoenician inscriptions and by hostile witnesses in the Hebrew Bible and classical authors.",
  "reflects": "Cosmic order modeled as contested political sovereignty — the world runs the way a throne is won, held, and lost.",
  "sources": [
   "Mark S. Smith, 'The Ugaritic Baal Cycle, Volume I' (1994)",
   "Mark S. Smith, 'The Early History of God: Yahweh and the Other Deities in Ancient Israel' (2nd ed. 2002)",
   "Dennis Pardee, 'Ritual and Cult at Ugarit' (2002)",
   "John Day, 'Yahweh and the Gods and Goddesses of Canaan' (2000)"
  ]
 },
 "candomble": {
  "essence": "An Afro-Brazilian initiatory religion forged by enslaved West and West-Central Africans and their descendants in Bahia — rooted in the colonial slave trade and taking institutional shape in the early nineteenth century — organized in autonomous temple communities (terreiros) grouped by 'nation': Ketu (Yoruba orixás), Jeje (Fon voduns), and Angola (Bantu inquices). It centers on serving the orixás, personified powers of nature and human life, through initiation, offering, and trance. Census declarations understate it — stigma long suppressed open affiliation — but its practice and cultural reach extend across Brazil.",
  "cosmos": "Olorun (Olodumare), the remote supreme creator, delegates the working of the world to the orixás, who are sustained and moved by axé, the transferable vital force concentrated in blood, leaves, stones, and consecrated objects. Each person belongs to a particular orixá who rules their head and shapes their disposition and destiny. At death the axexê funeral rite disengages the person's axé and spirit from the community; the eguns (spirits of the dead) are honored but kept ritually segregated from the orixá cult.",
  "practice": "Entry is by divination and initiation: the iaô undergoes seclusion and consecration to their orixá, emerging into a lifelong hierarchy under a mãe- or pai-de-santo (ialorixá/babalorixá). Regular obligations include ebó (offerings, including animal sacrifice), drum-driven public festivals in which initiates incorporate their orixás in possession trance, and cowrie-shell divination (jogo de búzios). The demands are concrete: food taboos, ritual duties, and seniority counted in years since initiation.",
  "canon": "No scripture: a liturgical-oral corpus of songs, praise-names, and orixá narratives in ritual Yoruba, Fon, and Bantu-derived language, transmitted within terreiros; ethnographic compendia such as Verger's 'Orixás' (1981) serve as reference works, not scripture.",
  "reflects": "Religion as embodied memory — a transplanted pantheon kept alive under slavery by seating the gods in human bodies through initiation and trance.",
  "sources": [
   "Roger Bastide, 'The African Religions of Brazil' (1960; Eng. tr. 1978)",
   "Pierre Fatumbi Verger, 'Orixás: Deuses Iorubás na África e no Novo Mundo' (1981)",
   "Ruth Landes, 'The City of Women' (1947)",
   "J. Lorand Matory, 'Black Atlantic Religion' (2005)"
  ]
 },
 "caodai": {
  "essence": "A Vietnamese syncretic monotheism founded in 1926 in Tây Ninh, French Cochinchina, following Ngô Văn Chiêu's 1921 vision of the Divine Eye and séance revelations to a circle of Vietnamese functionaries and notables led by Lê Văn Trung and Phạm Công Tắc. Its full name, Đại Đạo Tam Kỳ Phổ Độ ('Great Way of the Third Universal Salvation'), states the central claim: the one God behind all prior religions has returned to unite them in a final dispensation. Adherents number on the order of a few million, mostly in southern Vietnam, with diaspora congregations in France, the United States, and Australia.",
  "cosmos": "Cao Đài ('Highest Tower'), identified in the revelations with the Jade Emperor and with the God of the Abrahamic faiths, governs through a celestial constitutional order: the invisible Bát Quái Đài, a divine legislature of buddhas, immortals, and saints, issues law transmitted to earth through mediums. History unfolds as three amnesties of revelation — Buddhism, Taoism, Confucianism, and Christianity belonging to the first two — with the present, third amnesty delivered directly by God rather than through regional founders. Souls transmigrate under karma, ascending a hierarchy of perfection toward reunion with the Supreme Being, while the Holy Mother (Diêu Trì Kim Mẫu) presides over the birth of souls.",
  "practice": "Adherents keep four daily prayer sessions (6 a.m., noon, 6 p.m., midnight) before an altar bearing the Divine Eye, observe graded vegetarianism (ten days per month for the committed, full vegetarianism at higher ranks), and follow Confucian-inflected precepts. A nine-graded clergy modeled partly on Catholic hierarchy — pope (Giáo Tông), censor-cardinals, archbishops, down through student priests, with women eligible up to cardinal rank — administers the religion from the Tây Ninh Holy See. Spirit-writing séances using the cơ bút basket-planchette generated the canon and clerical appointments; official séances have been suspended since the 1975 communist takeover.",
  "canon": "The 'Thánh Ngôn Hiệp Tuyển' (Compilation of Divine Messages), the 'Pháp Chánh Truyền' (Religious Constitution, 1926), and the 'Tân Luật' (New Canonical Code) — all received by séance in the founding years.",
  "reflects": "Syncretism made institutional — the unification of all religions pursued not as private mystical insight but as an administrative, constitutional project with God as head of state.",
  "sources": [
   "Victor L. Oliver, 'Caodai Spiritism: A Study of Religion in Vietnamese Society' (1976)",
   "Janet Hoskins, 'The Divine Eye and the Diaspora: Vietnamese Syncretism Becomes Transpacific Caodaism' (2015)",
   "Jérémy Jammes, 'Les Oracles du Cao Đài' (2014)",
   "R. B. Smith, 'An Introduction to Caodaism' (1970)"
  ],
  "flagged": [
   "Post-1975 suspension of official séances is well reported (Hoskins, Jammes), but limited spirit-writing continues in some dissident and diaspora branches — the cutoff is not absolute.",
   "Adherent counts vary widely by source (roughly 1–5 million); I give only an order of magnitude."
  ]
 },
 "cargo-cult": {
  "essence": "A family of Melanesian millenarian movements — in Papua New Guinea, Vanuatu, the Solomons, and western New Guinea — arising under colonial rule from the late nineteenth century and intensifying around the World Wars, in which prophets announced that ancestors or a savior figure would return bearing 'cargo': the manufactured wealth Europeans possessed but were never seen to make. The John Frum movement on Tanna and the Yaohnanen veneration of Prince Philip survive as living communities. The label 'cargo cult' itself is a colonial-era coinage (first in print in 1945) that many anthropologists now treat as a distorting category rather than a neutral description.",
  "cosmos": "The movements share a moral economy of the cosmos: manufactured goods are produced or sanctioned by the ancestors, so their maldistribution is a spiritual scandal — the whites intercepted what the dead intended for their own kin. An imminent reversal (Koreri on Biak, John Frum's promised day on Tanna) will return the dead, abolish colonial labor and money, and open an age of abundance; in Biak's Manseren myth the millennium includes bodily renewal, imaged as the shedding of skin. The eschatology is emphatically this-worldly and near.",
  "practice": "Prophet-led and episodic: communities have destroyed gardens, pigs, and money to force the new age; cleared airstrips and built bamboo control towers, warehouses, and flagpoles in ritual replication of colonial and military logistics; drilled as uniformed 'armies' (John Frum Day is kept each 15 February on Tanna); and in the 1919 Vailala movement, amid mass trembling, abandoned and destroyed their own traditional cult objects. What the movements ask is radical divestment now against total abundance to come.",
  "canon": "No texts of their own — authority is prophetic and oral; the documentary corpus is ethnographic, above all F. E. Williams on Vailala (1923), Worsley's 'The Trumpet Shall Sound' (1957), Lawrence's 'Road Belong Cargo' (1964), and Kamma's 'Koreri' (1972).",
  "reflects": "Religion as a theory of production and just distribution — the sacred invoked to explain where wealth comes from and to whom it is rightfully owed.",
  "sources": [
   "Peter Worsley, 'The Trumpet Shall Sound: A Study of Cargo Cults in Melanesia' (1957)",
   "Peter Lawrence, 'Road Belong Cargo' (1964)",
   "Lamont Lindstrom, 'Cargo Cult: Strange Stories of Desire from Melanesia and Beyond' (1993)",
   "F. C. Kamma, 'Koreri: Messianic Movements in the Biak-Numfor Culture Area' (1972)"
  ],
  "flagged": [
   "The 1945 first-print date for the term follows Lindstrom's history of the word; I am confident of the decade, slightly less of the exact year."
  ]
 },
 "castaneda": {
  "essence": "Not an ethnic tradition but a literary fabrication that functioned as one: Carlos Castaneda's Don Juan books (1968–1998) presented themselves as UCLA anthropological fieldwork recording an apprenticeship to a Yaqui sorcerer, don Juan Matus. The 'fieldwork' earned Castaneda a doctorate (1973) and the books sold in the millions, seeding a real following that outlived their exposure. Richard de Mille's source criticism (1976, 1980) documented the forgery: internal chronologies contradicted by library records placing Castaneda at UCLA during his claimed desert fieldwork, an absence of genuinely Yaqui content, and passages traceable in bulk to prior published sources.",
  "cosmos": "As doctrine, the books teach that ordinary reality is only a learned 'description': the tonal (the ordered island of the known) floats within the nagual (the unknowable), and the sorcerer shifts worlds by moving the 'assemblage point' of perception. In the later books, awareness is food for the Eagle at death, and the warrior's aim is to burn 'with the fire from within' and slip past with consciousness intact. The system is a bricolage of Mesoamerican vocabulary, Asian and Western mysticism, phenomenology, and 1960s psychedelia rather than any attested Yaqui cosmology.",
  "practice": "As promulgated: 'stopping the world,' erasing personal history, 'recapitulation' of one's life, controlled dreaming, and — in the early books only — psychotropic allies (peyote, datura, mushroom smoke), later demoted to training aids. In the 1990s Castaneda's inner circle marketed Tensegrity, choreographed 'magical passes,' through the Cleargreen corporation. The costs were real: followers organized their lives around a fictitious lineage, and several women of the inner circle vanished immediately after Castaneda's 1998 death — the remains of one, Patricia Partin, were later found in Death Valley.",
  "canon": "Twelve books, 'The Teachings of Don Juan: A Yaqui Way of Knowledge' (1968) through 'The Active Side of Infinity' (1998); the counter-canon is Richard de Mille's 'Castaneda's Journey' (1976) and 'The Don Juan Papers' (1980).",
  "reflects": "The appetite for credentialed exotic wisdom — a fabricated ethnography functioned as scripture for decades, showing that claims of authentication, not content alone, can power a tradition; kept in the atlas as the fake shard against which real seams are measured.",
  "sources": [
   "Richard de Mille, 'Castaneda's Journey: The Power and the Allegory' (1976)",
   "Richard de Mille (ed.), 'The Don Juan Papers: Further Castaneda Controversies' (1980)",
   "Jay Courtney Fikes, 'Carlos Castaneda, Academic Opportunism and the Psychedelic Sixties' (1993)",
   "Amy Wallace, 'Sorcerer's Apprentice: My Life with Carlos Castaneda' (2003)"
  ],
  "flagged": [
   "The post-1998 disappearances and the identification of Patricia Partin's remains rest on investigative journalism (Robert Marshall, Salon, 2007), not academic scholarship."
  ]
 },
 "celtic": {
  "essence": "The pre-Christian religion of the Celtic-speaking peoples of Iron Age Europe — Gaul, Britain, Ireland, Iberia, the Alpine lands, and Galatia — from roughly the Hallstatt/La Tène horizon through Romanization and Christianization. No insider account survives: the religion must be triangulated from archaeology, Greco-Roman testimony, Romano-Celtic inscriptions, and medieval Irish and Welsh literature written down centuries later by Christians.",
  "cosmos": "No unified cosmology is attested. The evidence points to sanctity concentrated in the land itself — springs, rivers, groves (nemeton), and waters receiving deliberate deposits — and, in the Insular literature, an Otherworld adjacent to this one, entered through burial mounds (síd), water, or mist. Classical authors report druidic teaching that souls do not perish but pass into other bodies (Caesar, Diodorus), a doctrine they compared to Pythagorean transmigration.",
  "practice": "In Gaul and Britain a professional priestly-juridical class, the druids, taught orally, judged disputes, and presided over sacrifice; classical sources allege human sacrifice (with evident polemical interest), and finds such as the Lindow Man bog body are argued both ways. Votive deposition — weapons, cauldrons, and metalwork sunk in water — is the best-attested ritual act archaeologically. Early Irish literature preserves the quarter-day festivals Samain, Imbolc, Beltaine, and Lugnasad, along with sacral-kingship rites; how far these generalize to the ancient Continent is uncertain.",
  "canon": "None native — the druids declined to commit their teaching to writing (Caesar, Gallic War 6.14). The sources are external: Posidonian ethnography via Caesar, Strabo, and Diodorus; epigraphy and iconography (the Coligny calendar, dedications to Taranis, Epona, Lugus); and the Christian-era Irish sagas (Táin Bó Cúailnge, Lebor Gabála Érenn) and the Welsh Mabinogi.",
  "reflects": "Sanctity located in landscape rather than text — and a standing demonstration of how little of a purely oral religion survives except through the accounts of outsiders and successors.",
  "sources": [
   "Miranda Green, 'The Gods of the Celts' (1986)",
   "Ronald Hutton, 'Blood and Mistletoe: The History of the Druids in Britain' (2009)",
   "Barry Cunliffe, 'The Ancient Celts' (1997)",
   "Proinsias Mac Cana, 'Celtic Mythology' (1970)"
  ],
  "flagged": [
   "The four Irish quarter-day festivals are attested only in medieval Irish sources; their observance by continental Celts is unevidenced and stated here as Irish-specific."
  ]
 },
 "channeling": {
  "essence": "A late-twentieth-century American metaphysical current in which discarnate intelligences are held to speak or write through entranced humans: Jane Roberts's 'Seth' (from 1963), Helen Schucman's inner dictation published as 'A Course in Miracles' (scribed 1965–72), and JZ Knight's 'Ramtha' (from 1977) are the type cases. Descended from nineteenth-century Spiritualist mediumship but shifted from contacting the dead to receiving book-length metaphysical curricula, it supplied the New Age movement's core doctrine: you create your own reality.",
  "cosmos": "Consciousness is primary and matter its projection — Seth calls the physical world a 'camouflage' constructed by belief; ACIM calls it an illusion born of the ego's dream of separation from God. The self is a local projection of a larger multidimensional entity or oversoul living many lives simultaneously; time is not linear; death is a change of focus rather than an ending, with reincarnation across probable realities. There is no hell and no external judgment — experience is understood as self-selected for the soul's education.",
  "practice": "Largely unchurched and book-mediated: study groups (ACIM's 365-lesson Workbook makes it literally a curriculum), workshops and recorded sessions with channels, and private belief-auditing and affirmation. The main institutional exception is Ramtha's School of Enlightenment (Yelm, Washington, founded 1988), which runs residential disciplines. What the current asks of adherents is cognitive: examine and revise beliefs, since experience is treated as their printout.",
  "canon": "Jane Roberts, 'The Seth Material' (1970), 'Seth Speaks' (1972), and 'The Nature of Personal Reality' (1974); 'A Course in Miracles' (1976); and Ramtha's dictated teachings, collected as 'Ramtha: The White Book'.",
  "reflects": "Revelation privatized and ongoing — scripture production relocated from ancient prophets to the entranced individual, with authority resting on psychological resonance rather than institutional warrant.",
  "sources": [
   "Michael F. Brown, 'The Channeling Zone: American Spirituality in an Anxious Age' (1997)",
   "Wouter J. Hanegraaff, 'New Age Religion and Western Culture' (1996)",
   "J. Gordon Melton, 'Finding Enlightenment: Ramtha's School of Ancient Wisdom' (1998)"
  ]
 },
 "chaos-magic": {
  "essence": "A results-oriented occult current founded in late-1970s Yorkshire by Peter J. Carroll and Ray Sherwin, loosely institutionalized in the Illuminates of Thanateros (announced 1978, reorganized as 'the Pact' in 1987). Its practitioners — individual magicians and small working groups, mostly in Britain, Germany, and North America — treat belief itself as the instrument of magic rather than its precondition, under the adopted motto 'Nothing is true, everything is permitted.'",
  "cosmos": "Deliberately anti-doctrinal: reality is treated as probabilistic and locally malleable, minds impose 'paradigms' upon it, and any cosmology — theist, pagan, psychological, science-fictional — may be adopted temporarily for what it can do. Gods and spirits are handled operationally as psychological constructs or egregores (belief-fed thought-forms) without ruling on their ultimate status, so there is no stable teaching about death or afterlife. Carroll's 'Liber Kaos' (1992) dresses the system in quantum-flavored formalism.",
  "practice": "Core techniques: sigilization (Austin Osman Spare's method of condensing a desire into an abstract glyph and firing it during 'gnosis'), attainment of gnosis by excitatory means (dance, pain, orgasm) or inhibitory ones (fasting, trance), construction of servitors, and disciplined paradigm-shifting — adopting and discarding whole belief systems as exercises. Results are logged in a magical diary; the ethic is pragmatic, and what the current demands is experimental honesty rather than devotion.",
  "canon": "Peter J. Carroll, 'Liber Null' (1978) and 'Liber Kaos' (1992); Ray Sherwin, 'The Book of Results' (1978); Phil Hine, 'Condensed Chaos' (1995); with Austin Osman Spare's 'The Book of Pleasure' (1913) as the acknowledged precursor.",
  "reflects": "Religion reduced to technique — belief handled as disposable software and judged purely by operational results, isolating the instrumental impulse from the doctrinal one.",
  "sources": [
   "Colin Duggan, 'Perennialism and Iconoclasm: Chaos Magick and the Legitimacy of Innovation', in Egil Asprem & Kennet Granholm (eds.), 'Contemporary Esotericism' (2013)",
   "Hugh B. Urban, 'Magia Sexualis: Sex, Magic, and Liberation in Modern Western Esotericism' (2006)",
   "Dave Evans, 'The History of British Magick After Crowley' (2007)"
  ],
  "flagged": [
   "Founding details (exact dates and places in Yorkshire, the IOT's earliest form) are thinly documented outside practitioner accounts; I give the conventional 1976–78 window."
  ]
 },
 "cheondoism": {
  "essence": "Korea's first organized indigenous new religion: Donghak ('Eastern Learning'), founded in 1860 when the impoverished rural aristocrat Choe Je-u (Su-un) received a revelation from Hanullim, the Lord of Heaven; he was executed for heterodoxy in 1864. Renamed Cheondogyo ('Religion of the Heavenly Way') in 1905 under Son Byeong-hui, it teaches that Heaven dwells within every person, fueled the 1894 Donghak Peasant Revolution, and supplied leading figures of the 1919 March First independence movement. Today it is small in South Korea and nominally represented in the North by the Chondoist Chongu Party; grouped with it here is the related Jeungsan family of movements (Daesoon Jinrihoe, Jeung San Do) descending from Kang Il-sun.",
  "cosmos": "Hanullim is not a transcendent monarch apart from the world but the ultimate energy (jigi) pervading it: every person 'bears the Heavenly Lord' (sicheonju), so humanity and Heaven are ontologically one (in-nae-cheon). History stands at the Gaebyeok, the Great Opening, in which the exhausted 'Early Heaven' of hierarchy and conflict gives way to a 'Later Heaven' of mutual flourishing — a transformation to be realized in this world as an earthly paradise rather than in a separate hereafter. In the Jeungsan stream, Kang Il-sun (1871–1909) taught that the cosmic order itself required his ritual 'reordering work' (cheonji gongsa) and the resolution of accumulated grievances (haewon sangsaeng) before the new age can open.",
  "practice": "Cheondogyo prescribes five devotions (ogwan): the twenty-one-syllable incantation (jumun), the offering of a bowl of pure water (cheongsu), weekly Sunday assembly (siil), setting aside 'sincerity rice' (seongmi) as offering, and prayer (gido). Its ethic converts the theology directly into conduct — 'treat people as Heaven' (sa-in-yeo-cheon) — which historically grounded anti-caste and anti-colonial activism. The Jeungsan organizations maintain their own devotional systems of incantation and ritual centered on Kang's works.",
  "canon": "Choe Je-u's 'Donggyeong Daejeon' (Great Compendium of Eastern Scripture, in literary Chinese) and 'Yongdam Yusa' (Songs of Yongdam, vernacular Korean verse), published posthumously in 1880–81 by his successor Choe Si-hyeong; the Jeungsan bodies canonize collections of Kang Il-sun's acts and sayings, such as Daesoon Jinrihoe's 'Jeon-gyeong'.",
  "reflects": "Mysticism converted directly into social equality — the divinization of the ordinary person deployed as an argument against caste, empire, and hierarchy.",
  "sources": [
   "Don Baker, 'Korean Spirituality' (2008)",
   "Carl F. Young, 'Eastern Learning and the Heavenly Way: The Tonghak and Ch'ondogyo Movements and the Twilight of Korean Independence' (2014)",
   "George L. Kallander, 'Salvation through Dissent: Tonghak Heterodoxy and Early Modern Korea' (2013)",
   "Benjamin B. Weems, 'Reform, Rebellion, and the Heavenly Way' (1964)"
  ],
  "flagged": [
   "Cheondoists as leaders of the March First movement: the standard count is 15 of the 33 declaration signers, headed by Son Byeong-hui; I state the role generally rather than committing to the exact figure."
  ]
 },
 "cherokee": {
  "essence": "The traditional religion of the Cherokee (Aniyunwiya), an Iroquoian-speaking people of the southern Appalachians, continued today by the Eastern Band in North Carolina and, after the 1838–39 Removal, by the Cherokee Nation and United Keetoowah Band in Oklahoma. It is a cosmology of maintained balance — between Upper and Under Worlds, purity and pollution, humans and animals — kept through ceremony, medicine, and daily practice, now lived alongside and interwoven with Christianity, with the stomp grounds keeping fire and dance active.",
  "cosmos": "This World is a great island floating on the sea, suspended from the solid sky vault by cords at the four cardinal points; above lies the ordered Upper World of the Sun, Moon, and Thunderers, below a chaotic Under World of water and monsters such as the horned serpent Uktena. The earth began as mud fetched from beneath the primal sea by the water beetle Dayuni'si and was shaped by the Great Buzzard's wingbeats. In Mooney's myth corpus, disease was invented by offended animals and medicine offered by sympathetic plants; the dead travel west to Tsusgina'i, the ghost country in Usunhi'yi, the Darkening Land.",
  "practice": "Purification by 'going to water' — ritual immersion at dawn — precedes and punctuates important undertakings; the Green Corn ceremony renews the sacred fire, remits grievances, and honors the first harvest of Selu's corn; all-night stomp dances around the fire remain the core communal rite. Medicine people apply sacred formulas — spoken texts for curing, hunting, love, and protection, written down after 1821 in the Sequoyan syllabary by practitioners themselves. Seven matrilineal clans structure marriage and ritual responsibility.",
  "canon": "An oral corpus, uniquely supplemented by native-script manuscripts: the syllabary formula-books documented in Mooney's 'The Sacred Formulas of the Cherokees' (1891) and the Swimmer Manuscript, alongside the narratives of his 'Myths of the Cherokee' (1900).",
  "reflects": "Religion as equilibrium engineering — a cosmos strung between ordered and chaotic poles, kept livable through constant, precise acts of purification and balance.",
  "sources": [
   "James Mooney, 'Myths of the Cherokee' (1900)",
   "James Mooney, 'The Sacred Formulas of the Cherokees' (1891)",
   "James Mooney & Frans M. Olbrechts, 'The Swimmer Manuscript: Cherokee Sacred Formulas and Medicinal Prescriptions' (1932)",
   "Charles Hudson, 'The Southeastern Indians' (1976)"
  ]
 },
 "chewa": {
  "essence": "The traditional religion of the Chewa, a matrilineal Bantu-speaking people of Malawi, eastern Zambia, and Mozambique, heirs of the Maravi confederacy. It joins a withdrawn sky-creator (Chiuta/Chauta), territorial rain shrines served by spirit-mediums, active family ancestors (mizimu), and the men's Nyau secret society, whose Gule Wamkulu masquerade — proclaimed by UNESCO in 2005 — remains vigorous alongside pervasive Christianity.",
  "cosmos": "At the rock of Kaphirintiwa, God, the first humans, and the animals descended together in a thunderstorm onto still-soft stone, leaving footprints; the primal unity ended when humans invented fire, scorching the earth, scattering the animals, and driving Chiuta into the sky — a withdrawal etiology rather than a fall into sin. Chiuta remains the source of rain, manifest in thunder and the rainbow, but daily religious traffic runs through nearer powers: the mizimu, the family dead, who protect when fed and withdraw when neglected, and great serpent spirits of the pools bound up with rain. Witchcraft (ufiti) accounts for malice, illness, and misfortune.",
  "practice": "Men are initiated in bush seclusion into Nyau and thereafter dance Gule Wamkulu at funerals and initiations, embodying wild-animal and spirit characters with de facto license to transgress and satirize; women's ritual authority runs through chinamwali initiation and, historically, the great rain shrines — at Msinja the prophetess Makewana, 'mother of all people,' delivered Chiuta's edicts in trance. Households offer flour and beer to the mizimu, and diviner-healers (sing'anga) diagnose misfortune and counter ufiti. Among the neighboring Mang'anja of the lower Shire valley, the martyr rain-cult of Mbona shows the same territorial-shrine architecture.",
  "canon": "An oral corpus — cosmogonic myth, mask lore, and shrine tradition — with no native scripture; the scholarly record runs chiefly through Schoffeleers, Rangeley, and van Breugel.",
  "reflects": "Structural counterbalance as religion — a matrilineal society granting men a parallel, masked spiritual sovereignty, with social and cosmic equilibrium negotiated between the two.",
  "sources": [
   "J. Matthew Schoffeleers, 'River of Blood: The Genesis of a Martyr Cult in Southern Malawi, c. A.D. 1600' (1992)",
   "J. M. Schoffeleers (ed.), 'Guardians of the Land: Essays on Central African Territorial Cults' (1979)",
   "J. W. M. van Breugel, 'Chewa Traditional Religion' (2001)",
   "Brian Morris, 'Animals and Ancestors: An Ethnography' (2000)"
  ],
  "flagged": [
   "Kaphirintiwa is usually localized in the Dzalanyama range on the Malawi–Mozambique border; accounts vary, so precise geography is omitted."
  ]
 },
 "chinese-folk": {
  "essence": "The diffuse communal religion of Han Chinese populations in mainland China, Taiwan, and the diaspora: worship of gods (shen) arrayed as a celestial bureaucracy under the Jade Emperor, veneration of family ancestors, and propitiation of ghosts. It has no founder, membership, or church — it lives in household, lineage, village temple, and festival — and by participation it is among the largest bodies of religious practice on earth, revived vigorously on the mainland since the 1980s.",
  "cosmos": "The spirit world mirrors imperial society, classically schematized by Arthur Wolf as gods, ghosts, and ancestors: gods are the celestial officialdom (City Gods, Earth Gods, the Kitchen God filing his New Year report), ancestors are one's own senior kin, and ghosts are the neglected or unrelated dead — dangerous strangers. The dead pass through the underworld courts of the Ten Kings (a Buddhist–Daoist synthesis) and depend on descendants' offerings of food and spirit money. Divine status is meritocratic and provisional: a god's efficacy (ling) is proven by answered prayers and forfeited by failure, the path by which deified humans such as Mazu and Guan Yu rose through the ranks.",
  "practice": "Daily incense at household altars and ancestral tablets; temple offerings and vows, with divination by moon-blocks (jiaobei) and numbered lot-sticks; a festival cycle including New Year, Qingming grave-sweeping, and the seventh-month Ghost Festival; processions and pilgrimages on gods' birthdays, the Dajia Mazu pilgrimage in Taiwan among the largest. Spirit mediums (tang-ki) speak for gods in trance in Hokkien and other regional communities. It keeps no clergy of its own, hiring Daoist priests or Buddhist monks for rites as needed; what it asks is reciprocity — keep the offerings, debts, and reports current.",
  "canon": "No canon: an oral-ritual repertoire carried by temple custom, morality books (shanshu), opera, and vernacular novels — 'Journey to the West' and the 'Fengshen Yanyi' (Investiture of the Gods) supplied much of the popular pantheon's imagery.",
  "reflects": "Divinity modeled on government and audited by results — the transactional, civic face of the religious impulse, where worship is a working relationship rather than a creed.",
  "sources": [
   "Arthur P. Wolf (ed.), 'Religion and Ritual in Chinese Society' (1974)",
   "C. K. Yang, 'Religion in Chinese Society' (1961)",
   "Adam Yuet Chau, 'Miraculous Response: Doing Popular Religion in Contemporary China' (2006)",
   "Valerie Hansen, 'Changing Gods in Medieval China, 1127–1276' (1990)"
  ]
 },
 "chinese": {
  "essence": "The classical religio-philosophical mainstream of China: from Shang oracle-bone divination and Zhou worship of Shangdi/Tian, through the axial-age texts — the Yijing, the Daodejing and Zhuangzi, the Confucian classics — to organized religious Daoism (from the Celestial Masters' revelation, traditionally 142 CE) and the imperial state cult that lasted until the end of the empire. Its bearers ranged from court diviners and literati to Daoist priests and self-cultivators; its central claim is that reality follows an impersonal normative pattern — Heaven's mandate, the Dao, the alternation of yin and yang — with which human order must align.",
  "cosmos": "No creator god stands at the root: the Dao generates the one, the two, and the ten thousand things (Daodejing 42), and the world is a self-ordering process of qi articulated by the complementary polarity of yin and yang — the Yijing's sixty-four hexagrams model its permutations of change. Heaven (Tian) sanctions and revokes rulership through the Mandate (tianming), read in omens and in the people's welfare. Classical ancestral religion assumes the dead persist — the hun soul ascending, the po remaining with the body — and depend on descendants' sacrifice; religious Daoism added programs for transcendence (xian immortality) through alchemy and self-cultivation.",
  "practice": "Divination, from cracked oracle bones to yarrow-stalk consultation of the Yijing; ancestor sacrifice at household and lineage altars; the emperor's calendrical sacrifices to Heaven as the state's supreme rite; and Daoist liturgy, precepts, meditation, and internal alchemy (neidan) administered by ordained priests. Confucian ritual propriety (li) extends the cult into everyday social form. What it asks is alignment — of conduct, state, and body — with the given pattern.",
  "canon": "The Yijing (Zhou-era core with the 'Ten Wings' commentaries), the Daodejing and Zhuangzi, and the Confucian Five Classics; religious Daoism's revelations are gathered in the Daozang (Daoist Canon, 1445 Ming edition).",
  "reflects": "The ultimate as pattern rather than person — an impersonal normative order occupying the place other traditions give to a creator's will.",
  "sources": [
   "Julia Ching, 'Chinese Religions' (1993)",
   "Kristofer Schipper, 'The Taoist Body' (1993)",
   "Michael J. Puett, 'To Become a God: Cosmology, Sacrifice, and Self-Divinization in Early China' (2002)"
  ]
 },
 "christianity": {
  "essence": "The global religion confessing Jesus of Nazareth as the Christ — the incarnate Son of God, crucified under Pontius Pilate around 30 CE and raised bodily from the dead. Beginning as a Jewish messianic movement, it became the largest religion on earth, roughly 2.3–2.4 billion people across Catholic, Orthodox, Protestant, and independent churches. Its central claim is that in this one execution and resurrection God reconciled the world to himself.",
  "cosmos": "One God, eternally triune (Father, Son, Holy Spirit), creates the world from nothing and good; humanity's primal rebellion (the Fall) introduces sin and death; God enters history as a particular human being, and the cross and resurrection accomplish redemption. History is linear and ends in Christ's return, the resurrection of the body, final judgment, and a renewed creation — not the soul's escape from matter but matter's glorification. Traditions differ on the interim state of the dead (immediate presence with God, purgation, or sleep until the resurrection), but heaven and hell mark the final alternatives.",
  "practice": "Entry by baptism; sustained by the Eucharist and weekly assembly on Sunday, the day of resurrection; ordered by a liturgical year climaxing at Easter. The ethical core is the double command — love of God and neighbor — elaborated through traditions of almsgiving, monasticism, and mission. Institutional forms span the episcopal hierarchies of Rome and the Orthodox East to congregational independency; sacramental counts and church order divide the families, while the Nicene Creed largely unites them.",
  "canon": "The Bible: the Old Testament (the Hebrew Scriptures, with deuterocanonical books in Catholic and Orthodox use) and the twenty-seven-book New Testament; the ecumenical creeds function as the canonical rule of interpretation.",
  "reflects": "Transcendence reconciled with history through one mediating person — the incarnational impulse, with victory located paradoxically in defeat.",
  "sources": [
   "Henry Chadwick, 'The Early Church' (1967)",
   "Jaroslav Pelikan, 'The Christian Tradition: A History of the Development of Doctrine', 5 vols. (1971–1989)",
   "Diarmaid MacCulloch, 'Christianity: The First Three Thousand Years' (2009)"
  ]
 }
};
